INSERT INTO `article_sentences` (`sentence_id`, `article_id`, `sentence_order`, `original_text`, `translation`, `is_favorite`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'Chapter Fourteen', '第十四章', 0, '2025-11-19 00:13:49', NULL),
(2, 1, 2, 'Frank, too, was thinking that life is strange.', '弗兰克也在想，生活真奇怪。', 0, '2025-11-19 00:13:49', NULL),
(3, 1, 3, 'He was also thinking that for a private detective, Percival Smidgely was a very slow driver.', '他还在想，作为一名私家侦探，珀西瓦尔·斯米杰利开车很慢。', 0, '2025-11-19 00:13:49', NULL),
(4, 1, 4, '"Can you go any faster?" he said to Percival.', '“你能开快点吗？”他对珀西瓦尔说。', 0, '2025-11-19 00:13:49', NULL),
(5, 1, 5, '"I''m trying to let Polly keep up," said Percival.', '“我在尽量让波利跟上，”珀西瓦尔说。', 0, '2025-11-19 00:13:49', NULL),
(6, 1, 6, '"Polly?"', '“波利？”', 0, '2025-11-19 00:13:49', NULL),
(7, 1, 7, '"The pigeon," said Percival. "She seems interested in coming along."', '“那只鸽子，”珀西瓦尔说，“她似乎很想跟着来。”', 0, '2025-11-19 00:13:49', NULL),
(8, 1, 8, 'Frank slowly turned and looked.', '弗兰克慢慢转过身看了看。', 0, '2025-11-19 00:13:49', NULL),
(9, 1, 9, 'There was, indeed, a pigeon flying behind the car.', '确实，有一只鸽子在车后飞着。', 0, '2025-11-19 00:13:49', NULL),
(10, 1, 10, 'The pigeon was flapping her wings mightily.', '那只鸽子正使劲地拍打着翅膀。', 0, '2025-11-19 00:13:49', NULL),
(11, 1, 11, 'She had a determined look on her face.', '她脸上带着坚定的神情。', 0, '2025-11-19 00:13:49', NULL),
(12, 2, 1, 'Chapter Four', '第四章', 0, '2025-11-28 18:05:42', NULL),
(13, 2, 2, 'Mercy Watson represented joy, chaos, possibility.', '梅西·沃森代表着欢乐、混乱与可能性。', 0, '2025-11-28 18:05:42', NULL),
(14, 2, 3, 'Without her, Baby Lincoln felt as if a layer of glumness had settled over the world.', '没有她，贝贝·林肯感觉世界仿佛笼罩上了一层阴郁。', 0, '2025-11-28 18:05:42', NULL),
(15, 2, 4, 'Apparently, Eugenia did not feel the same way.', '显然，尤金妮亚并没有同样的感受。', 0, '2025-11-28 18:05:42', NULL),
(16, 2, 5, 'When Baby returned home, she found Eugenia dancing around the living room, playing a jig on the accordion.', '当贝贝回到家时，她发现尤金妮亚在客厅里跳着吉格舞，还在手风琴上演奏着舞曲。', 0, '2025-11-28 18:05:42', NULL),
(17, 2, 6, 'Baby said, “Sister, Mercy Watson is missing.”', '贝贝说：“姐姐，梅西·沃森不见了。”', 0, '2025-11-28 18:05:42', NULL),
(18, 2, 7, '“Yes,” said Eugenia. “I know. That pig has been the bane of my existence, and this is a happy, happy day.”', '“是的，”尤金妮亚说，“我知道。那头猪一直是我生活的祸根，而今天是个非常非常开心的日子。”', 0, '2025-11-28 18:05:42', NULL),
(19, 2, 8, '“Oh, sister,” said Baby. “You shouldn’t take joy in other people’s suffering.”', '“哦，姐姐，”贝贝说，“你不应该从别人的痛苦中获得快乐。”', 0, '2025-11-28 18:05:42', NULL),
(20, 2, 9, '“Schadenfreude,” said Eugenia.', '“幸灾乐祸（德语词），”尤金妮亚说。', 0, '2025-11-28 18:05:42', NULL),
(21, 2, 10, '“How’s that?” said Baby.', '“那是什么？”贝贝问。', 0, '2025-11-28 18:05:42', NULL),
(22, 2, 11, '“Schadenfreude is the word for taking joy in', '“幸灾乐祸（Schadenfreude）就是指从……中获得快乐”', 0, '2025-11-28 18:05:42', NULL),
(23, 2, 12, '21', '21（页码）', 0, '2025-11-28 18:05:42', NULL),
(24, 3, 1, 'thought that he wouldn''t mind getting a good, long look at Percival Smidgey''s private investigator''s license.', '他觉得自己不会介意好好仔细看看珀西瓦尔·斯米吉的私家侦探执照。', 0, '2025-12-01 10:57:08', NULL),
(25, 3, 2, 'Still, when they arrived at the Butter Barrel factory, Frank let Percival Smidgey take the lead.', '不过，当他们到达黄油桶工厂时，弗兰克让珀西瓦尔·斯米吉带路。', 0, '2025-12-01 10:57:08', NULL),
(26, 3, 3, '“I''ll be right back, Polly,” said Percival to the pigeon, who was resting on the hood of the car.', '“我马上回来，波利，”珀西瓦尔对那只停在汽车引擎盖上的鸽子说。', 0, '2025-12-01 10:57:08', NULL),
(27, 3, 4, 'And studying the factory with beady-eyed interest.', '并且饶有兴致地（用那双明亮的小眼睛）打量着工厂。', 0, '2025-12-01 10:57:08', NULL),
(28, 3, 5, 'The Butter Barrel factory was a welcoming sort of place.', '黄油桶工厂是个挺让人舒心的地方。', 0, '2025-12-01 10:57:08', NULL),
(29, 3, 6, 'There were automatic doors that opened to admit Percival and Frank and then whooshed shut behind them.', '那里有自动门，珀西瓦尔和弗兰克进去后，门就呼地一声在他们身后关上了。', 0, '2025-12-01 10:57:08', NULL),
(30, 3, 7, '“Welcome to the Butter Barrel factory, where we fill every barrel with butter!” said a smiling receptionist.', '“欢迎来到黄油桶工厂，我们的每一个桶都装满了黄油！”一位面带微笑的接待员说道。', 0, '2025-12-01 10:57:08', NULL),
(31, 3, 8, '“Seen a pig?” said Percival.', '“见过猪吗？”珀西瓦尔问道。', 0, '2025-12-01 10:57:08', NULL),
(32, 3, 9, '“Pardon me?” said the receptionist, who was wearing a name tag that said SUSIE and underneath that were the words WE PUT BUTTER IN EVERY BARREL!', '“您说什么？”接待员问道，她戴着一个写着“苏西”的姓名牌，下面还有一行字：“我们每个桶里都装黄油！”', 0, '2025-12-01 10:57:08', NULL),
(33, 3, 10, '“Have you seen A. Pig?” said Percival in a very loud voice.', '“你见过A·猪吗？”珀西瓦尔大声问道。', 0, '2025-12-01 10:57:08', NULL),
(34, 3, 11, '“A pig?” said Susie. She looked from side to side. “Why would I have seen a pig? Is this some kind of particle joke?”', '“猪？”苏西问道。她左右看了看。“我为什么会见过猪？这是某种文字游戏吗？”', 0, '2025-12-01 10:57:08', NULL),
(35, 3, 12, '“Particle joke?” said Frank.', '“文字游戏？”弗兰克问道。', 0, '2025-12-01 10:57:08', NULL),
(36, 3, 13, '“This is not a joke of any sort,” said Percival', '“这根本不是什么玩笑，”珀西瓦尔说', 0, '2025-12-01 10:57:08', NULL),
(37, 4, 1, 'You might have to call Animal Control.', '你可能得给动物管理部门打电话。', 0, '2025-12-01 11:03:07', NULL),
(38, 4, 2, '"Animal Control?" said Mr. Watson. He felt his face getting warm.', '“动物管理部门？”沃森先生说。他感觉自己的脸变热了。', 0, '2025-12-01 11:03:07', NULL),
(39, 4, 3, 'He hung up the phone without even saying good - bye.', '他甚至没说再见就挂了电话。', 0, '2025-12-01 11:03:07', NULL),
(40, 4, 4, 'Mr. Watson felt humiliated, dispirited, at sea.', '沃森先生感到屈辱、沮丧，茫然无措。', 0, '2025-12-01 11:03:07', NULL),
(41, 4, 5, 'What was the world coming to when the fire department couldn''t assist a person in a time of crisis?', '在危急时刻消防部门都不能帮助一个人，这世界到底怎么了？', 0, '2025-12-01 11:03:07', NULL),
(42, 4, 6, '"What did they say?" said Mrs. Watson. "Are they on their way?"', '“他们怎么说？”沃森太太问。“他们在路上了吗？”', 0, '2025-12-01 11:03:07', NULL),
(43, 4, 7, '"I''ve been advised to call Animal Control," said Mr. Watson.', '“有人建议我给动物管理部门打电话，”沃森先生说。', 0, '2025-12-01 11:03:07', NULL),
(44, 4, 8, '"Oh, Mr. Watson," said Mrs. Watson.', '“哦，沃森先生，”沃森太太说。', 0, '2025-12-01 11:03:07', NULL),
(45, 4, 9, '"Don''t worry," he said. "I think I''ll just go and make some toast, in case she comes home," said Mr. Watson.', '“别担心，”他说。“我想我还是去做点吐司吧，万一她回家了呢，”沃森先生说。', 0, '2025-12-01 11:03:07', NULL),
(46, 4, 10, '"Excellent idea," said Mr. Watson.', '“好主意，”沃森先生说。', 0, '2025-12-01 11:03:07', NULL),
(47, 4, 11, 'He sighed a heavy sigh. He stared at the phone.', '他重重地叹了口气。他盯着电话。', 0, '2025-12-01 11:03:07', NULL),
(48, 4, 12, 'And then he picked it up and dialed.', '然后他拿起电话拨了号。', 0, '2025-12-01 11:03:07', NULL),
(49, 4, 13, '"Animal Control," said a voice on the other end. "This is Francine Poulet."', '“动物管理部门，”电话那头传来一个声音。“我是弗朗辛·普莱。”', 0, '2025-12-01 11:03:07', NULL),
(50, 4, 14, 'The smell of toast wafted from the kitchen.', '吐司的香味从厨房飘了出来。', 0, '2025-12-01 11:03:07', NULL),
(51, 4, 15, 'Mr. Watson heard Mrs. Watson crying. He hated it when Mrs. Watson cried.', '沃森先生听到沃森太太在哭。他最讨厌沃森太太哭的时候。', 0, '2025-12-01 11:03:07', NULL),
(52, 4, 16, '"Miss Poulet," said Mr. Watson. "This is Mr. Watson over on Deckawoo Drive. We''re looking', '“普莱小姐，”沃森先生说。“我是德卡武大道的沃森先生。我们正在找（这里原文可能未完整，但按现有内容翻译）”', 0, '2025-12-01 11:03:07', NULL),
