INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(1, 'a', 'a', '[{"example": "A cat stole my sandwich!", "meaning": "一个（用于单数可数名词前，表示非特定事物）", "part_of_speech": "indefinite article", "example_chinese": "一只猫偷了我的三明治！"}, {"example": "I eat a cookie a day to stay happy.", "meaning": "每（表示比率）", "part_of_speech": "preposition", "example_chinese": "我每天吃一块饼干来保持开心。"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:40:42'),
(5, 'about', 'about', '[{"example": "Let''s talk about cats wearing hats!", "meaning": "关于", "part_of_speech": "preposition", "example_chinese": "我们来聊聊戴帽子的猫吧！"}, {"example": "I ate about a million cookies today.", "meaning": "大约", "part_of_speech": "adverb", "example_chinese": "我今天吃了大约一百万块饼干。"}, {"example": "The puppy ran about like a furry tornado.", "meaning": "到处", "part_of_speech": "adverb", "example_chinese": "小狗像毛茸茸的龙卷风一样到处跑。"}, {"example": "Get ready, the show is about to start!", "meaning": "即将", "part_of_speech": "adjective", "example_chinese": "准备好，演出即将开始！"}]', '', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 10:40:48'),
(7, 'above', 'above', '[{"example": "The cat is above the fridge, planning world domination.", "meaning": "在...上面", "part_of_speech": "preposition", "example_chinese": "猫在冰箱上面，计划着统治世界。"}, {"example": "Look up! The UFO is flying above.", "meaning": "在上面", "part_of_speech": "adverb", "example_chinese": "看上面！UFO正在上方飞。"}, {"example": "Follow the above instructions to build a time machine.", "meaning": "上述的", "part_of_speech": "adjective", "example_chinese": "按照上述说明来造一台时间机器。"}]', '', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 10:40:19'),
(8, 'address', 'address', '[{"example": "I''ll address this pizza problem by eating it all!", "meaning": "处理，解决", "part_of_speech": "verb", "example_chinese": "我要通过吃掉整个披萨来解决这个披萨问题！"}, {"example": "My cat''s address is ''Under the Sofa, Crumbs Street''.", "meaning": "地址", "part_of_speech": "noun", "example_chinese": "我的猫的地址是''面包屑街，沙发底下''。"}, {"example": "He addressed the grumpy cactus as ''Mr. Prickles''.", "meaning": "称呼", "part_of_speech": "verb", "example_chinese": "他把那棵脾气暴躁的仙人掌称为''刺刺先生''。"}]', '', 'A1', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 10:40:20'),
(10, 'adult', 'adult', '[{"example": "An adult is someone who can eat cake for breakfast but chooses not to.", "meaning": "成年人", "part_of_speech": "noun", "example_chinese": "成年人就是那种可以早餐吃蛋糕但选择不吃的人。"}, {"example": "My cat tries to act adult, but still chases its tail.", "meaning": "成年的；成熟的", "part_of_speech": "adjective", "example_chinese": "我的猫试图表现得成熟，但还是会追自己的尾巴。"}]', '', 'A1', 'medium', 'people: appearance', '2025-10-20 08:00:00', '2025-10-21 10:40:27'),
(11, 'after', 'after', '[{"example": "The cat ran after the laser dot like a tiny furry rocket!", "meaning": "在...之后", "part_of_speech": "preposition", "example_chinese": "猫咪追着激光点跑，像毛茸茸的小火箭！"}, {"example": "He ate the whole pizza and felt sleepy after.", "meaning": "后来", "part_of_speech": "adverb", "example_chinese": "他吃完整张披萨，后来就犯困了。"}, {"example": "After I finish this ice cream, I''ll need another one!", "meaning": "在...以后", "part_of_speech": "conjunction", "example_chinese": "吃完这个冰淇淋后，我还得再来一个！"}, {"example": "In the after years, he became a professional napper.", "meaning": "后来的", "part_of_speech": "adjective", "example_chinese": "在往后的岁月里，他成了职业打盹专家。"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:40:35'),
(12, 'afternoon', 'afternoon', '[{"example": "The cat takes a nap every afternoon at 3 PM sharp!", "meaning": "下午", "part_of_speech": "noun", "example_chinese": "这只猫每天下午3点整准时打盹！"}]', '/ˌɑːftəˈnuːn/', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:40:26'),
(13, 'again', 'again', '[{"example": "My dog ate my homework, so I have to do it again!", "meaning": "再次，又一次", "part_of_speech": "adverb", "example_chinese": "我的狗吃了我的作业，所以我得重做一遍！"}, {"example": "After the magic trick, the rabbit was back in the hat again.", "meaning": "回到原处或原状", "part_of_speech": "adverb", "example_chinese": "魔术表演后，兔子又回到了帽子里。"}]', '/əˈɡen/', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:40:34'),
(14, 'age', 'age', '[{"example": "My dog''s age is a secret—he says he''s 21 in dog years!", "meaning": "年龄", "part_of_speech": "noun", "example_chinese": "我狗的年龄是个秘密——它说自己按狗年算21岁了！"}, {"example": "In the age of smartphones, my grandpa still uses a brick phone for fun.", "meaning": "时代", "part_of_speech": "noun", "example_chinese": "在智能手机时代，我爷爷还在用砖头手机找乐子。"}, {"example": "If cheese can age beautifully, why can''t I?", "meaning": "变老", "part_of_speech": "verb", "example_chinese": "如果奶酪能优雅地变老，为什么我不行？"}]', '/eɪdʒ/', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:40:39'),
(15, 'all', 'all', '[{"example": "All cats secretly dream of world domination.", "meaning": "所有的，全部的", "part_of_speech": "adjective", "example_chinese": "所有猫咪都偷偷梦想统治世界。"}, {"example": "When the pizza arrived, it was gone in 60 seconds – we ate all!", "meaning": "所有人/事物", "part_of_speech": "pronoun", "example_chinese": "披萨送到后60秒就消失了——我们全吃光了！"}, {"example": "After the marathon, my legs were all wobbly like jelly.", "meaning": "完全地", "part_of_speech": "adverb", "example_chinese": "跑完马拉松后，我的腿像果冻一样完全抖个不停。"}]', '/ɔːl/', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 10:40:20'),
(17, 'all right', 'all right', '[{"example": "Is your coffee all right?", "meaning": "好的；安全的；可接受的", "part_of_speech": "adjective", "example_chinese": "你的咖啡还行吗？"}, {"example": "She sings all right in the shower.", "meaning": "满意地；顺利地", "part_of_speech": "adverb", "example_chinese": "她在淋浴时唱得还不错。"}, {"example": "All right, let''s go to the park!", "meaning": "好吧；行（表示同意）", "part_of_speech": "interjection", "example_chinese": "好吧，我们去公园吧！"}]', '/ˌɔːl ˈraɪt/', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:45:03'),
(19, 'lot', 'a lot', '[{"example": "I like ice cream a lot!", "meaning": "非常；很多", "part_of_speech": "adverb", "example_chinese": "我非常喜欢冰淇淋！"}, {"example": "She has a lot of toys.", "meaning": "大量；许多", "part_of_speech": "pronoun", "example_chinese": "她有很多玩具。"}]', '', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 10:45:02'),
(20, 'lot', 'a lot/lots', '[{"example": "I have a lot of toys!", "meaning": "大量，许多", "part_of_speech": "pronoun", "example_chinese": "我有很多玩具！"}, {"example": "She laughs a lot.", "meaning": "非常，很", "part_of_speech": "adverb", "example_chinese": "她经常大笑。"}, {"example": "We ate lots of candy.", "meaning": "大量（与lots互换使用）", "part_of_speech": "pronoun", "example_chinese": "我们吃了很多糖果。"}]', '/ə ˈlɒt/', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 10:44:55'),
(21, 'alright', 'alright', '[{"example": "Is it alright if I eat your last cookie?", "meaning": "没问题的，可以的", "part_of_speech": "adjective", "example_chinese": "我吃掉你最后一块饼干可以吗？"}, {"example": "The party went alright, everyone had fun!", "meaning": " satisfactorily 令人满意地", "part_of_speech": "adverb", "example_chinese": "派对进行得很顺利，大家都玩得很开心！"}, {"example": "Alright, let''s go to the park now!", "meaning": "好的，行（表示同意）", "part_of_speech": "interjection", "example_chinese": "好的，我们现在去公园吧！"}]', '', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 10:44:57'),
(22, 'also', 'also', '[{"example": "I like apples. I also like bananas.", "meaning": "也；同样", "part_of_speech": "adverb", "example_chinese": "我喜欢苹果。我也喜欢香蕉。"}, {"example": "He is smart. He is also very kind.", "meaning": "此外；而且", "part_of_speech": "adverb", "example_chinese": "他很聪明。而且他还非常友善。"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:45:09'),
(23, 'always', 'always', '[{"example": "The sun always rises in the east.", "meaning": "总是，一直", "part_of_speech": "adverb", "example_chinese": "太阳总是从东方升起。"}, {"example": "I will always love you.", "meaning": "永远", "part_of_speech": "adverb", "example_chinese": "我会永远爱你。"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:45:10'),
(24, 'a.m.', 'a.m.', '[{"example": "The cat naps at 9 a.m. every day!", "meaning": "上午（午夜到中午）", "part_of_speech": "noun", "example_chinese": "这只猫每天上午9点打盹！"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:45:02'),
(25, 'an', 'an', '[{"example": "An apple a day keeps the doctor away!", "meaning": "一个（用于元音音素开头的单词前）", "part_of_speech": "article", "example_chinese": "一天一个苹果，医生远离我！"}, {"example": "I saw an elephant in my dream.", "meaning": "某一个", "part_of_speech": "article", "example_chinese": "我梦里看到了一头大象。"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:45:10'),
(26, 'and', 'and', '[{"example": "I like apples and bananas.", "meaning": "和，与，而且", "part_of_speech": "conjunction", "example_chinese": "我喜欢苹果和香蕉。"}, {"example": "He woke up and brushed his teeth.", "meaning": "然后，接着", "part_of_speech": "conjunction", "example_chinese": "他醒来然后刷牙。"}]', '', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 10:45:17'),
(29, 'animal', 'animal', '[{"example": "The lion is a wild animal.", "meaning": "动物", "part_of_speech": "noun", "example_chinese": "狮子是一种野生动物。"}, {"example": "He acted like an animal when he was angry.", "meaning": "兽性的人", "part_of_speech": "noun", "example_chinese": "他生气时表现得像个野兽。"}]', '', 'A1', 'medium', 'animals', '2025-10-20 08:00:00', '2025-10-21 10:44:53'),
(30, 'answer', 'answer', '[{"example": "The answer to the question is 42.", "meaning": "回答，答案", "part_of_speech": "noun", "example_chinese": "这个问题的答案是42。"}, {"example": "Please answer the phone when it rings.", "meaning": "回答，答复", "part_of_speech": "verb", "example_chinese": "电话响时请接一下。"}]', '', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 10:46:15'),
(32, 'any', 'any', '[{"example": "Do you have any cookies?", "meaning": "任何", "part_of_speech": "determiner", "example_chinese": "你有任何饼干吗？"}, {"example": "Choose any you like!", "meaning": "任何一个", "part_of_speech": "pronoun", "example_chinese": "选你喜欢的任何一个！"}, {"example": "Is the soup any good?", "meaning": "稍微", "part_of_speech": "adverb", "example_chinese": "这汤稍微好喝吗？"}]', '', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 10:46:47'),
(34, 'anything', 'anything', '[{"example": "You can ask me anything!", "meaning": "任何事物；无论什么", "part_of_speech": "pronoun", "example_chinese": "你可以问我任何事！"}, {"example": "Is this cake anything like the one your mom makes?", "meaning": "在任何程度上；根本（用于否定句或疑问句）", "part_of_speech": "adverb", "example_chinese": "这个蛋糕和你妈妈做的有一点点像吗？"}]', '', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 10:46:46'),
