(177, 'different', 'different', '[{"example": "My sister and I have different favorite colors.", "meaning": "不同的", "part_of_speech": "adjective", "example_chinese": "我姐姐和我有不同最喜欢的颜色。"}, {"example": "We saw different animals at the zoo.", "meaning": "各种各样的", "part_of_speech": "adjective", "example_chinese": "我们在动物园看到了各种各样的动物。"}]', 'ˈdɪf.ər.ənt', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 11:05:35'),
(178, 'difficult', 'difficult', '[{"example": "This puzzle is difficult, but I love it!", "meaning": "困难的，艰难的", "part_of_speech": "adjective", "example_chinese": "这个拼图很难，但我超喜欢！"}, {"example": "My cat is difficult when choosing food.", "meaning": "难相处的，不易取悦的", "part_of_speech": "adjective", "example_chinese": "我的猫在选食物时很挑剔。"}]', 'ˈdɪf.ɪ.kəlt', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 11:05:53'),
(179, 'dining room', 'dining room', '[{"example": "We eat dinner in the dining room every night.", "meaning": "餐厅", "part_of_speech": "noun", "example_chinese": "我们每晚在餐厅吃晚饭。"}]', 'ˈdaɪ.nɪŋˌruːm', 'A1', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 11:05:46'),
(180, 'dinner', 'dinner', '[{"example": "We eat dinner at 7 PM.", "meaning": "晚餐", "part_of_speech": "noun", "example_chinese": "我们晚上7点吃晚餐。"}, {"example": "Sunday dinner is my favorite meal.", "meaning": "正餐", "part_of_speech": "noun", "example_chinese": "周日的正餐是我最喜欢的一餐。"}]', 'ˈdɪn.ər', 'A1', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 11:05:53'),
(181, 'do', 'do', '[{"example": "I do my homework every day.", "meaning": "做，干", "part_of_speech": "verb", "example_chinese": "我每天都做作业。"}, {"example": "Do you like ice cream?", "meaning": "助动词（用于构成疑问句或否定句）", "part_of_speech": "verb", "example_chinese": "你喜欢冰淇淋吗？"}, {"example": "She runs faster than I do.", "meaning": "代替其他动词以避免重复", "part_of_speech": "verb", "example_chinese": "她跑得比我快。"}, {"example": "We had a big do for her birthday.", "meaning": "聚会，社交活动", "part_of_speech": "noun", "example_chinese": "我们为她的生日办了个大聚会。"}]', 'duː', 'A1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 11:06:01'),
(184, 'doctor', 'doctor', '[{"example": "The doctor wears a funny hat.", "meaning": "医生", "part_of_speech": "noun", "example_chinese": "医生戴着一顶滑稽的帽子。"}, {"example": "My sister is a doctor of science.", "meaning": "博士", "part_of_speech": "noun", "example_chinese": "我姐姐是科学博士。"}, {"example": "He tried to doctor the photo.", "meaning": "篡改", "part_of_speech": "verb", "example_chinese": "他试图篡改照片。"}]', 'ˈdɒk.tər', 'A1', 'medium', 'body and health, work', '2025-10-20 08:00:00', '2025-10-21 11:07:17'),
(185, 'dog', 'dog', '[{"example": "The little dog runs fast.", "meaning": "狗", "part_of_speech": "noun", "example_chinese": "小狗跑得很快。"}, {"example": "Bad luck dogs him all day.", "meaning": "跟踪；困扰", "part_of_speech": "verb", "example_chinese": "坏运气整天困扰着他。"}]', 'dɒg', 'A1', 'medium', 'animals', '2025-10-20 08:00:00', '2025-10-21 11:06:01'),
(186, 'doll', 'doll', '[{"example": "The little girl hugs her doll every night.", "meaning": "玩具娃娃", "part_of_speech": "noun", "example_chinese": "小女孩每晚都抱着她的娃娃。"}, {"example": "You look like a doll in that dress!", "meaning": "漂亮的人（俚语）", "part_of_speech": "noun", "example_chinese": "你穿那条裙子真漂亮！"}, {"example": "She dolled up for the party.", "meaning": "精心打扮", "part_of_speech": "verb", "example_chinese": "她为派对精心打扮。"}]', 'dɒl', 'A1', 'medium', 'shopping', '2025-10-20 08:00:00', '2025-10-21 11:06:11'),
(187, 'dollar', 'dollar', '[{"example": "I found a dollar on the street!", "meaning": "美元（货币单位）", "part_of_speech": "noun", "example_chinese": "我在街上捡到了一美元！"}, {"example": "This candy costs five dollars.", "meaning": "元（泛指货币单位）", "part_of_speech": "noun", "example_chinese": "这颗糖果要五块钱。"}]', 'ˈdɒl.ər', 'A1', 'medium', 'money', '2025-10-20 08:00:00', '2025-10-21 11:06:09'),
(188, 'forget', 'Don''t forget...', '[{"example": "Don''t forget to smile every day!", "meaning": "不要忘记...", "part_of_speech": "phrase", "example_chinese": "别忘了每天都要微笑！"}, {"example": "Don''t forget your umbrella when it rains.", "meaning": "记住要...", "part_of_speech": "phrase", "example_chinese": "下雨时别忘了带伞。"}, {"example": "Don''t forget we have a test tomorrow!", "meaning": "记得...", "part_of_speech": "phrase", "example_chinese": "别忘了我们明天有考试！"}]', '/dəʊnt fəˈɡet/', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 11:06:16'),
(189, 'worry', 'Don''t worry (about sth)', '[{"example": "Don''t worry about the test, you''ll do great!", "meaning": "别担心（某事）", "part_of_speech": "phrase", "example_chinese": "别担心考试，你会考得很好的！"}, {"example": "Don''t worry, I''ll help you with your homework.", "meaning": "别着急", "part_of_speech": "phrase", "example_chinese": "别着急，我会帮你做作业的。"}, {"example": "Don''t worry about what he said, he didn''t mean it.", "meaning": "别放在心上", "part_of_speech": "phrase", "example_chinese": "别把他说的话放在心上，他不是故意的。"}]', '/dəʊnt ˈwʌri əˈbaʊt (sʌmθɪŋ)/', 'A1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 11:06:22'),
(190, 'door', 'door', '[{"example": "The cat ran out the door.", "meaning": "门", "part_of_speech": "noun", "example_chinese": "猫从门跑出去了。"}, {"example": "The store door is always open.", "meaning": "出入口", "part_of_speech": "noun", "example_chinese": "商店的门总是开着。"}, {"example": "Learning opens the door to success.", "meaning": "途径", "part_of_speech": "noun", "example_chinese": "学习是通往成功的途径。"}]', 'dɔːr', 'A1', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 11:06:21'),
(191, 'do', 'do the cleaning/cooking, etc.', '[{"example": "I do the cleaning while my brother does the cooking.", "meaning": "做清洁/做饭等家务", "part_of_speech": "verb phrase", "example_chinese": "我负责打扫，我哥哥负责做饭。"}, {"example": "Let''s do the cleaning together and finish faster!", "meaning": "承担日常家务", "part_of_speech": "verb phrase", "example_chinese": "我们一起打扫，这样能更快完成！"}]', '/duː ðə ˈkliːnɪŋ/ /kʊkɪŋ/', 'A1', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 11:06:26'),
(192, 'down', 'down', '[{"example": "The cat jumped down from the tree.", "meaning": "向下；在下面", "part_of_speech": "adverb", "example_chinese": "猫从树上跳了下来。"}, {"example": "We walked down the street.", "meaning": "沿着；往下", "part_of_speech": "preposition", "example_chinese": "我们沿着街道走。"}, {"example": "He felt down after losing the game.", "meaning": "情绪低落的；向下的", "part_of_speech": "adjective", "example_chinese": "输掉比赛后他情绪低落。"}, {"example": "She downed her juice in one gulp.", "meaning": "喝下；击倒", "part_of_speech": "verb", "example_chinese": "她一口气喝完了果汁。"}, {"example": "The duck''s down keeps it warm.", "meaning": "绒毛；软毛", "part_of_speech": "noun", "example_chinese": "鸭子的绒毛让它保持温暖。"}]', 'daʊn', 'A1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 11:06:36'),
