(198, 'driver', 'driver', '[{"example": "The bus driver smiled and waved.", "meaning": "司机", "part_of_speech": "noun", "example_chinese": "公交车司机微笑着挥手。"}, {"example": "I need to update the printer driver.", "meaning": "驱动程序", "part_of_speech": "noun", "example_chinese": "我需要更新打印机驱动程序。"}, {"example": "He hit the ball far with his driver.", "meaning": "高尔夫球杆", "part_of_speech": "noun", "example_chinese": "他用开球杆把球打得很远。"}]', 'ˈdraɪ.vər', 'A1', 'medium', 'travel, work', '2025-10-20 08:00:00', '2025-10-21 11:06:46'),
