(1501, 'especially', 'especially', '[{"example": "I love all fruits, especially strawberries.", "meaning": "特别地，尤其", "part_of_speech": "adverb", "example_chinese": "我喜欢所有水果，尤其是草莓。"}]', 'ɪˈspeʃ.əl.i', 'A2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 12:00:31'),
(1502, 'euro', 'euro', '[{"example": "I need to exchange my dollars for euros before traveling to Paris.", "meaning": "欧元", "part_of_speech": "noun", "example_chinese": "我去巴黎旅行前需要把美元换成欧元。"}]', 'ˈjʊə.rəʊ', 'A2', 'medium', 'money', '2025-10-20 08:00:00', '2025-10-21 12:00:32'),
(1503, 'even', 'even', '[{"example": "He can''t even spell his own name.", "meaning": "甚至", "part_of_speech": "adverb", "example_chinese": "他甚至不会拼写自己的名字。"}, {"example": "The table has an even surface.", "meaning": "平坦的", "part_of_speech": "adjective", "example_chinese": "这张桌子表面平坦。"}, {"example": "She evened the dough with a roller.", "meaning": "使平坦", "part_of_speech": "verb", "example_chinese": "她用擀面杖把面团擀平。"}]', 'ˈIː.vən', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:39'),
(1504, 'ever', 'ever', '[{"example": "Have you ever visited Paris?", "meaning": "曾经；在任何时候", "part_of_speech": "adverb", "example_chinese": "你曾经去过巴黎吗？"}, {"example": "I will love you forever and ever.", "meaning": "永远；始终", "part_of_speech": "adverb", "example_chinese": "我会永远永远爱你。"}]', 'ˈev.ər', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:39'),
(1505, 'everybody', 'everybody', '[{"example": "Everybody loves the weekend!", "meaning": "每个人，大家", "part_of_speech": "pronoun", "example_chinese": "大家都喜欢周末！"}]', 'ˈev.riˌbɒd.i', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:39'),
(1506, 'everyone', 'everyone', '[{"example": "Everyone loves the sunny weather.", "meaning": "每个人，人人", "part_of_speech": "pronoun", "example_chinese": "每个人都喜欢晴朗的天气。"}]', 'ˈev.ri.wʌn', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:44'),
(1507, 'everything', 'everything', '[{"example": "Everything is ready for the party.", "meaning": "一切事物，所有东西", "part_of_speech": "noun", "example_chinese": "派对的一切都准备好了。"}]', 'ˈev.ri.θɪŋ', 'A2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 12:00:44'),
(1508, 'everywhere', 'everywhere', '[{"example": "Children are playing everywhere in the park.", "meaning": "到处，各处", "part_of_speech": "adverb", "example_chinese": "孩子们在公园里到处玩耍。"}]', 'ˈev.ri.weər', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:34'),
(1509, 'exactly', 'exactly', '[{"example": "The train arrived exactly at 3 o''clock.", "meaning": "精确地，完全地", "part_of_speech": "adverb", "example_chinese": "火车正好在3点到达。"}, {"example": "\"So we need to be careful?\" \"Exactly!\"", "meaning": "确实如此（表示赞同）", "part_of_speech": "adverb", "example_chinese": "\"所以我们需要小心？\" \"确实如此！\""}]', 'ɪgˈzækt.li', 'A2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 12:00:52'),
(1510, 'exam', 'exam', '[{"example": "I have a math exam tomorrow.", "meaning": "考试", "part_of_speech": "noun", "example_chinese": "我明天有数学考试。"}]', 'ɪgˈzæm', 'A2', 'medium', 'education', '2025-10-20 08:00:00', '2025-10-21 12:00:49'),
(1511, 'examination', 'examination', '[{"example": "I have a math examination tomorrow.", "meaning": "考试", "part_of_speech": "noun", "example_chinese": "我明天有一场数学考试。"}, {"example": "The doctor did a careful examination of my eyes.", "meaning": "检查", "part_of_speech": "noun", "example_chinese": "医生仔细检查了我的眼睛。"}]', 'ɪgˌzæm.ɪˈneɪ.ʃən', 'A2', 'medium', 'education', '2025-10-20 08:00:00', '2025-10-21 12:00:56'),
(1512, 'excellent', 'excellent', '[{"example": "She got an excellent score on her test.", "meaning": "极好的，优秀的", "part_of_speech": "adjective", "example_chinese": "她在考试中取得了极好的成绩。"}]', 'ˈek.səl.ənt', 'A2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 12:00:53'),
(1513, 'except', 'except', '[{"example": "Everyone came except Tom.", "meaning": "除了", "part_of_speech": "preposition", "example_chinese": "除了汤姆大家都来了。"}, {"example": "I''d go except it''s too far.", "meaning": "除了", "part_of_speech": "conjunction", "example_chinese": "我想去除了太远了。"}, {"example": "We excepted him from the list.", "meaning": "排除", "part_of_speech": "verb", "example_chinese": "我们把他从名单中排除了。"}]', 'ɪkˈsept', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:00:48'),
(1515, 'exercise', 'exercise', '[{"example": "Running is good exercise for your heart.", "meaning": "锻炼；运动", "part_of_speech": "noun", "example_chinese": "跑步是对心脏有益的运动。"}, {"example": "Please do the math exercises on page 10.", "meaning": "练习；习题", "part_of_speech": "noun", "example_chinese": "请完成第10页的数学练习题。"}]', 'ˈek.sə.saɪz', 'A2', 'medium', 'body and health, people: actions, shopping', '2025-10-20 08:00:00', '2025-10-21 12:01:00'),
(1517, 'exit', 'exit', '[{"example": "The emergency exit is on your left.", "meaning": "出口", "part_of_speech": "noun", "example_chinese": "紧急出口在你的左边。"}, {"example": "Please exit the building quietly.", "meaning": "离开", "part_of_speech": "verb", "example_chinese": "请安静地离开大楼。"}]', 'ˈek.sɪt', 'A2', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 12:00:58'),
(1519, 'explain', 'explain', '[{"example": "Can you explain this game to me?", "meaning": "解释；说明", "part_of_speech": "verb", "example_chinese": "你能给我解释一下这个游戏吗？"}]', 'ɪkˈspleɪn', 'A2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 12:01:01'),
(1520, 'extra', 'extra', '[{"example": "Can I have extra cheese on my pizza?", "meaning": "额外的", "part_of_speech": "adjective", "example_chinese": "我的披萨能多加些奶酪吗？"}, {"example": "He worked as an extra in the movie.", "meaning": "临时演员", "part_of_speech": "noun", "example_chinese": "他在这部电影里当临时演员。"}, {"example": "This coffee is extra strong today.", "meaning": "特别地", "part_of_speech": "adverb", "example_chinese": "今天的咖啡特别浓。"}]', 'ˈek.strə', 'A2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 12:01:08'),
(1521, 'fact', 'fact', '[{"example": "It is a fact that the sun rises in the east.", "meaning": "事实", "part_of_speech": "noun", "example_chinese": "太阳从东方升起是一个事实。"}]', 'fækt', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:05'),
(1522, 'fail', 'fail', '[{"example": "I will not fail the exam this time.", "meaning": "失败；不及格", "part_of_speech": "verb", "example_chinese": "这次我不会考不及格。"}, {"example": "The project was a big fail.", "meaning": "失败；不及格", "part_of_speech": "noun", "example_chinese": "这个项目是个大失败。"}]', 'feɪl', 'A2', 'medium', 'education', '2025-10-20 08:00:00', '2025-10-21 12:01:07'),
(1523, 'fair', 'fair', '[{"example": "The teacher is fair to all students.", "meaning": "公平的", "part_of_speech": "adjective", "example_chinese": "老师对所有学生都很公平。"}, {"example": "We bought honey at the country fair.", "meaning": "集市", "part_of_speech": "noun", "example_chinese": "我们在乡村集市买了蜂蜜。"}, {"example": "She has fair skin and blue eyes.", "meaning": "白皙的（皮肤）", "part_of_speech": "adjective", "example_chinese": "她皮肤白皙，蓝眼睛。"}]', 'feər', 'A2', 'medium', 'people: appearance', '2025-10-20 08:00:00', '2025-10-21 12:01:16'),
(1524, 'fall', 'fall', '[{"example": "The leaves change color in the fall.", "meaning": "秋天", "part_of_speech": "noun", "example_chinese": "树叶在秋天变色。"}, {"example": "Apples fall from the tree.", "meaning": "落下", "part_of_speech": "verb", "example_chinese": "苹果从树上落下。"}, {"example": "Don''t fall on the ice!", "meaning": "跌倒", "part_of_speech": "verb", "example_chinese": "别在冰上跌倒！"}]', 'fɔːl', 'A2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 12:01:14'),
(1525, 'fan', 'fan', '[{"example": "I turned on the fan because it was hot.", "meaning": "风扇；爱好者", "part_of_speech": "noun", "example_chinese": "因为天气热，我打开了风扇。"}, {"example": "She is a big fan of pop music.", "meaning": "粉丝；狂热爱好者", "part_of_speech": "noun", "example_chinese": "她是流行音乐的忠实粉丝。"}]', 'fæn', 'A2', 'medium', 'arts and media, people: personality, shopping', '2025-10-20 08:00:00', '2025-10-21 12:01:14'),
(1526, 'fantastic', 'fantastic', '[{"example": "The fireworks show was absolutely fantastic!", "meaning": "极好的，奇妙的", "part_of_speech": "adjective", "example_chinese": "烟花表演真是棒极了！"}, {"example": "He told us a fantastic story about dragons and magic.", "meaning": "异想天开的", "part_of_speech": "adjective", "example_chinese": "他给我们讲了一个关于龙和魔法的奇幻故事。"}]', 'fænˈtæs.tɪk', 'A2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 12:01:21'),
(1527, 'far', 'far', '[{"example": "The park is not far from here.", "meaning": "远地", "part_of_speech": "adverb", "example_chinese": "公园离这儿不远。"}, {"example": "He dreams of traveling to far countries.", "meaning": "遥远的", "part_of_speech": "adjective", "example_chinese": "他梦想去遥远的国家旅行。"}]', 'fɑːr', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:22'),
(1528, 'farmer', 'farmer', '[{"example": "The farmer grows corn and wheat.", "meaning": "农民", "part_of_speech": "noun", "example_chinese": "这位农民种植玉米和小麦。"}]', 'ˈfɑː.mər', 'A2', 'medium', 'work', '2025-10-20 08:00:00', '2025-10-21 12:01:26'),
(1529, 'fashion', 'fashion', '[{"example": "She always follows the latest fashion.", "meaning": "时尚；流行款式", "part_of_speech": "noun", "example_chinese": "她总是追随最新时尚。"}]', 'ˈfæʃ.ən', 'A2', 'medium', 'clothes, people: appearance', '2025-10-20 08:00:00', '2025-10-21 12:01:26'),
(1531, 'fast food', 'fast food', '[{"example": "I often eat fast food for lunch because it''s quick.", "meaning": "快餐", "part_of_speech": "noun", "example_chinese": "我午餐常吃快餐，因为它很快。"}]', 'ˌfɑːstˈfuːd', 'A2', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 12:01:28'),
(1532, 'field', 'field', '[{"example": "The children ran through the green field.", "meaning": "田地；田野", "part_of_speech": "noun", "example_chinese": "孩子们跑过绿色的田野。"}, {"example": "She is an expert in the field of science.", "meaning": "领域；专业", "part_of_speech": "noun", "example_chinese": "她是科学领域的专家。"}, {"example": "The players are on the football field.", "meaning": "运动场", "part_of_speech": "noun", "example_chinese": "球员们在足球场上。"}]', 'fiːld', 'A2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 12:01:23'),
(1533, 'fifth', 'fifth', '[{"example": "He finished fifth in the race.", "meaning": "第五", "part_of_speech": "noun", "example_chinese": "他在比赛中获得了第五名。"}, {"example": "She ate a fifth of the pizza.", "meaning": "五分之一", "part_of_speech": "noun", "example_chinese": "她吃了五分之一个披萨。"}]', 'fɪfθ', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:32'),
(1534, 'fifty', 'fifty', '[{"example": "My grandmother is fifty years old.", "meaning": "五十", "part_of_speech": "noun", "example_chinese": "我的奶奶五十岁了。"}]', 'ˈfɪf.ti', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:32'),
(1535, 'file', 'file', '[{"example": "I saved the document as a PDF file.", "meaning": "文件", "part_of_speech": "noun", "example_chinese": "我把文档保存为PDF文件。"}, {"example": "The police keep a file on every criminal.", "meaning": "档案", "part_of_speech": "noun", "example_chinese": "警方为每个罪犯都保留档案。"}, {"example": "You need to file your taxes before April.", "meaning": "提交", "part_of_speech": "verb", "example_chinese": "你需要在四月前报税。"}]', 'faɪl', 'A2', 'medium', 'technology', '2025-10-20 08:00:00', '2025-10-21 12:01:41'),
(1537, 'fill', 'fill', '[{"example": "Please fill the bottle with water.", "meaning": "填满；装满", "part_of_speech": "verb", "example_chinese": "请把瓶子装满水。"}, {"example": "I ate my fill of cake at the party.", "meaning": "填满的量；充足", "part_of_speech": "noun", "example_chinese": "我在派对上吃了足够多的蛋糕。"}]', 'fɪl', 'A2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 12:01:33'),
(1538, 'fill', 'fill in/out sth or fill sth in/out', '[{"example": "Please fill out this form with your personal information.", "meaning": "填写（表格或文件）", "part_of_speech": "phrasal verb", "example_chinese": "请用您的个人信息填写这张表格。"}, {"example": "The kids filled in the coloring book with bright crayons.", "meaning": "填满（空白处）", "part_of_speech": "phrasal verb", "example_chinese": "孩子们用鲜艳的蜡笔填满了涂色书。"}]', '/fɪl aʊt/', 'A2', 'medium', 'communication, people: actions', '2025-10-20 08:00:00', '2025-10-21 12:01:40'),
(1539, 'final', 'final', '[{"example": "This is my final decision.", "meaning": "最终的", "part_of_speech": "adjective", "example_chinese": "这是我的最终决定。"}, {"example": "Our team reached the basketball final.", "meaning": "决赛", "part_of_speech": "noun", "example_chinese": "我们队进入了篮球决赛。"}, {"example": "I need to study for my English final.", "meaning": "期末考试", "part_of_speech": "noun", "example_chinese": "我需要为英语期末考试学习。"}]', 'ˈfaɪ.nəl', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:47'),
(1540, 'finally', 'finally', '[{"example": "We finally reached the top of the mountain!", "meaning": "终于；最后", "part_of_speech": "adverb", "example_chinese": "我们终于到达了山顶！"}]', 'ˈfaɪ.nə.li', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:45'),
(1542, 'find', 'find out (sth) or find (sth) out', '[{"example": "I just found out that cats sleep 16 hours a day!", "meaning": "查明/发现", "part_of_speech": "phrasal verb", "example_chinese": "我刚发现猫每天睡16个小时！"}]', '/faɪnd aʊt/', 'A2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 12:01:46'),
(1544, 'finger', 'finger', '[{"example": "She wears a ring on her finger.", "meaning": "手指", "part_of_speech": "noun", "example_chinese": "她手指上戴着一枚戒指。"}]', 'ˈfɪŋ.gər', 'A2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 12:01:38'),
(1545, 'fire', 'fire', '[{"example": "We sat around the fire and told stories.", "meaning": "火", "part_of_speech": "noun", "example_chinese": "我们围坐在火堆旁讲故事。"}, {"example": "The firefighters quickly put out the fire.", "meaning": "火灾", "part_of_speech": "noun", "example_chinese": "消防员迅速扑灭了火灾。"}, {"example": "The boss had to fire the lazy employee.", "meaning": "解雇", "part_of_speech": "verb", "example_chinese": "老板不得不解雇了那个懒惰的员工。"}, {"example": "The soldier fired his gun at the target.", "meaning": "射击", "part_of_speech": "verb", "example_chinese": "士兵向目标开枪射击。"}]', 'faɪər', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:02:05'),
(1548, 'first name', 'first name', '[{"example": "My first name is Alex.", "meaning": "名字", "part_of_speech": "noun", "example_chinese": "我的名字是亚历克斯。"}]', 'ˈfɜːstˌneɪm', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:02:06'),
(1549, 'first', 'first of all', '[{"example": "First of all, let me introduce myself.", "meaning": "首先，第一", "part_of_speech": "adverb", "example_chinese": "首先，让我自我介绍一下。"}]', '/ˌfɜːst əv ˈɔːl/', 'A2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 12:01:50'),
(1551, 'fishing', 'fishing', '[{"example": "My grandfather loves fishing in the lake every weekend.", "meaning": "钓鱼", "part_of_speech": "noun", "example_chinese": "我爷爷喜欢每周末在湖里钓鱼。"}]', 'ˈfɪʃ.ɪŋ', 'A2', 'medium', 'shopping', '2025-10-20 08:00:00', '2025-10-21 12:01:50'),
(1552, 'fit', 'fit', '[{"example": "These shoes fit me perfectly.", "meaning": "适合；合身", "part_of_speech": "verb", "example_chinese": "这双鞋我穿正合适。"}, {"example": "He stays fit by running every day.", "meaning": "健康的；合适的", "part_of_speech": "adjective", "example_chinese": "他每天跑步保持健康。"}, {"example": "This shirt is a great fit!", "meaning": "适合；合身", "part_of_speech": "noun", "example_chinese": "这件衬衫非常合身！"}]', 'fɪt', 'A2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 12:01:55'),
(1553, 'flight', 'flight', '[{"example": "Our flight to Paris leaves at 3 PM.", "meaning": "航班；飞行", "part_of_speech": "noun", "example_chinese": "我们去巴黎的航班下午三点起飞。"}, {"example": "She ran up two flights of stairs.", "meaning": "楼梯的一段", "part_of_speech": "noun", "example_chinese": "她跑上了两段楼梯。"}]', 'flaɪt', 'A2', 'medium', 'travel', '2025-10-20 08:00:00', '2025-10-21 12:01:57'),
(1556, 'fog', 'fog', '[{"example": "The morning fog made the city look magical.", "meaning": "雾", "part_of_speech": "noun", "example_chinese": "晨雾让城市看起来像魔法世界。"}]', 'fɒg', 'A2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 12:02:36'),
(1557, 'foggy', 'foggy', '[{"example": "The morning was too foggy to see the mountains.", "meaning": "有雾的，雾气弥漫的", "part_of_speech": "adjective", "example_chinese": "早晨雾气太重，看不到山。"}, {"example": "My memory of that day is still foggy.", "meaning": "模糊的，不清楚的", "part_of_speech": "adjective", "example_chinese": "我对那天的记忆仍然模糊。"}]', 'ˈfɒg.i', 'A2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 12:02:02'),
