(1559, 'follow', 'follow', '[{"example": "The little duck will follow its mother.", "meaning": "跟随", "part_of_speech": "verb", "example_chinese": "小鸭子会跟着它的妈妈。"}, {"example": "Can you follow this story?", "meaning": "理解", "part_of_speech": "verb", "example_chinese": "你能理解这个故事吗？"}, {"example": "Please follow the rules in class.", "meaning": "遵循", "part_of_speech": "verb", "example_chinese": "请在课堂上遵守规则。"}]', 'ˈfɒl.əʊ', 'A2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 12:02:31'),
