(3433, 'brave', 'brave', '[{"example": "The brave firefighter saved the cat from the tree.", "meaning": "勇敢的", "part_of_speech": "adjective", "example_chinese": "勇敢的消防员从树上救下了小猫。"}, {"example": "She braved the storm to help her neighbors.", "meaning": "勇敢面对", "part_of_speech": "verb", "example_chinese": "她冒着暴风雨去帮助邻居。"}]', 'breɪv', 'B1', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 12:56:36'),
