(3437, 'half', 'break/cut, etc. sth in half', '[{"example": "She broke the chocolate in half to share with her friend.", "meaning": "将某物分成两半", "part_of_speech": "verb", "example_chinese": "她把巧克力掰成两半和朋友分享。"}, {"example": "He cut the apple in half with a knife.", "meaning": "将某物切成两半", "part_of_speech": "verb", "example_chinese": "他用刀把苹果切成两半。"}]', '/breɪk ɪn hɑːf/', 'B1', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 12:56:41'),
(3438, 'break', 'break down', '[{"example": "My car broke down on the highway.", "meaning": "发生故障", "part_of_speech": "verb", "example_chinese": "我的车在高速公路上抛锚了。"}, {"example": "She broke down when she heard the bad news.", "meaning": "情绪崩溃", "part_of_speech": "verb", "example_chinese": "听到坏消息时她崩溃大哭。"}, {"example": "Let''s break down this math problem step by step.", "meaning": "分解分析", "part_of_speech": "verb", "example_chinese": "让我们一步步分解这个数学题。"}]', '/breɪk daʊn/', 'B1', 'medium', 'technology', '2025-10-20 08:00:00', '2025-10-21 12:56:45'),
(3439, 'break', 'break in or break into sth ', '[{"example": "The thief broke into the house at midnight.", "meaning": "闯入；非法进入", "part_of_speech": "phrasal verb", "example_chinese": "小偷半夜闯入了房子。"}, {"example": "Everyone broke into applause when she finished singing.", "meaning": "突然开始（活动）", "part_of_speech": "phrasal verb", "example_chinese": "她唱完歌时，大家突然开始鼓掌。"}]', '/breɪk ˈɪntuː/', 'B1', 'medium', 'crime', '2025-10-20 08:00:00', '2025-10-21 12:56:30'),
(3440, 'break', 'break up', '[{"example": "They decided to break up last month.", "meaning": "分手", "part_of_speech": "verb", "example_chinese": "他们上个月决定分手了。"}, {"example": "The police will break up the crowd.", "meaning": "解散", "part_of_speech": "verb", "example_chinese": "警察将驱散人群。"}, {"example": "The party broke up at midnight.", "meaning": "结束", "part_of_speech": "verb", "example_chinese": "聚会在午夜结束了。"}]', '/breɪk ʌp/', 'B1', 'medium', 'education', '2025-10-20 08:00:00', '2025-10-21 12:56:50'),
(3442, 'breast', 'breast', '[{"example": "The baby is feeding at its mother''s breast.", "meaning": "胸部；乳房", "part_of_speech": "noun", "example_chinese": "婴儿正在母亲胸前吃奶。"}, {"example": "I''ll have the chicken breast with vegetables.", "meaning": "胸脯肉", "part_of_speech": "noun", "example_chinese": "我要一份鸡胸肉配蔬菜。"}, {"example": "He poured out his feelings from the bottom of his breast.", "meaning": "心情；内心", "part_of_speech": "noun", "example_chinese": "他从内心深处倾诉了自己的感受。"}]', 'brest', 'B1', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 12:56:51'),
(3443, 'breath', 'breath', '[{"example": "Take a deep breath and relax.", "meaning": "呼吸；气息", "part_of_speech": "noun", "example_chinese": "深呼吸然后放松。"}]', 'breθ', 'B1', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 12:56:50'),
