(3447, 'brief', 'brief', '[{"example": "We had a brief meeting this morning.", "meaning": "短暂的；简洁的", "part_of_speech": "adjective", "example_chinese": "今天早上我们开了个短会。"}, {"example": "The lawyer prepared a brief for the case.", "meaning": "简报；概要", "part_of_speech": "noun", "example_chinese": "律师为案件准备了简报。"}, {"example": "The manager will brief the team about the new project.", "meaning": "简要介绍", "part_of_speech": "verb", "example_chinese": "经理将向团队简要介绍新项目。"}]', 'briːf', 'B1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 12:57:00'),
