(7729, 'calm', 'calm down (sb) or calm (sb) down ', '[{"example": "The teacher told the excited children to calm down before the game.", "meaning": "使平静下来；冷静", "part_of_speech": "phrasal verb", "example_chinese": "老师让兴奋的孩子们在游戏前冷静下来。"}]', '/kɑːm daʊn/', 'B2', 'medium', 'communication, people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:30'),
(7730, 'calmly', 'calmly', '[{"example": "The cat sat calmly on the windowsill.", "meaning": "平静地，镇定地", "part_of_speech": "adverb", "example_chinese": "猫咪平静地坐在窗台上。"}]', 'ˈkɑːm.li', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:27'),
(7731, 'campus', 'campus', '[{"example": "The campus is full of cherry blossoms in spring.", "meaning": "校园", "part_of_speech": "noun", "example_chinese": "春天校园里开满了樱花。"}]', 'ˈkæm.pəs', 'B2', 'medium', 'education, buildings', '2025-10-20 08:00:00', '2025-10-21 14:40:32'),
(7734, 'reach', 'can/can''t/could, etc. reach (sth)', '[{"example": "I can''t reach the cookies on the top shelf.", "meaning": "够到/拿到", "part_of_speech": "verb", "example_chinese": "我够不到架子顶层的饼干。"}, {"example": "Could you reach him by phone yesterday?", "meaning": "联系到", "part_of_speech": "verb", "example_chinese": "你昨天能通过电话联系到他吗？"}, {"example": "The train can reach the station in 5 minutes.", "meaning": "到达", "part_of_speech": "verb", "example_chinese": "火车5分钟后就能到达车站。"}]', '/riːtʃ/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 14:40:35'),
(7736, 'canned', 'canned', '[{"example": "We bought canned peaches for the picnic.", "meaning": "罐装的", "part_of_speech": "adjective", "example_chinese": "我们为野餐买了罐装桃子。"}, {"example": "The audience laughed at the canned laughter.", "meaning": "录音/录像的", "part_of_speech": "adjective", "example_chinese": "观众对预录的笑声发出了笑声。"}, {"example": "He got canned from his job yesterday.", "meaning": "解雇", "part_of_speech": "verb", "example_chinese": "他昨天被解雇了。"}]', 'kænd', 'B2', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 14:40:42'),
(7737, 'bother', 'can''t be bothered', '[{"example": "I can''t be bothered to cook, let''s order pizza.", "meaning": "懒得做；不愿费心", "part_of_speech": "phrase", "example_chinese": "我懒得做饭，我们点披萨吧。"}]', '/kɑːnt bi ˈbɒðəd/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:40:40'),
(7738, 'get', 'can''t/couldn''t get over sth', '[{"example": "She couldn''t get over how big the watermelon had grown.", "meaning": "无法释怀/对…感到惊讶", "part_of_speech": "phrasal verb", "example_chinese": "她对西瓜长这么大感到不可思议。"}]', '/kɑːnt kʊdnt ɡet ˈəʊvər/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:40:41'),
(7739, 'tell', 'can tell', '[{"example": "I can tell you''re happy from your smile.", "meaning": "能分辨出；能看出来", "part_of_speech": "verb phrase", "example_chinese": "从你的笑容我能看出你很开心。"}]', '/kæn tel/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:35'),
(7740, 'face', 'can''t face sb/sth/doing sth ', '[{"example": "I can''t face another Monday morning meeting.", "meaning": "无法面对/不愿面对", "part_of_speech": "verb_phrase", "example_chinese": "我实在不想再面对周一早上的会议了。"}]', '/kɑːnt feɪs/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:47'),
(7741, 'eye', 'can''t keep/take your eyes off sb/sth', '[{"example": "He couldn''t keep his eyes off the glowing jellyfish in the dark aquarium.", "meaning": "目不转睛；无法移开视线", "part_of_speech": "idiom", "example_chinese": "他目不转睛地盯着黑暗水族箱里发光的海月水母。"}]', '/kɑːnt kiːp/ /teɪk jɔːr aɪz ɒf/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:40:47'),
(7742, 'take', 'can''t take sth', '[{"example": "I can''t take his loud music anymore.", "meaning": "无法忍受", "part_of_speech": "verb phrase", "example_chinese": "我再也受不了他吵闹的音乐了。"}]', '/kɑːnt teɪk/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:47'),
(7743, 'capable', 'capable', '[{"example": "She is capable of solving complex problems.", "meaning": "有能力的", "part_of_speech": "adjective", "example_chinese": "她有能力解决复杂问题。"}, {"example": "The capable engineer fixed the machine quickly.", "meaning": "能干的", "part_of_speech": "adjective", "example_chinese": "那位能干的工程师很快修好了机器。"}]', 'ˈkeɪ.pə.bl ̩', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:54'),
(7744, 'capable', 'capable of sth/doing sth ', '[{"example": "The little robot is capable of dancing.", "meaning": "能够做某事的", "part_of_speech": "adjective", "example_chinese": "这个小机器人能够跳舞。"}]', '/ˈkeɪpəbl əv/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:40:52'),
(7745, 'capacity', 'capacity', '[{"example": "The bottle has a capacity of two liters.", "meaning": "容量；能力", "part_of_speech": "noun", "example_chinese": "这个瓶子的容量是两升。"}, {"example": "She attended the meeting in her capacity as manager.", "meaning": "职位；身份", "part_of_speech": "noun", "example_chinese": "她以经理的身份参加了会议。"}]', 'kəˈpæs.ə.ti', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 14:40:55'),
(7748, 'capture', 'capture', '[{"example": "The photographer captured the beautiful sunset.", "meaning": "捕获", "part_of_speech": "verb", "example_chinese": "摄影师捕捉到了美丽的日落。"}, {"example": "The hero captured the villain in the story.", "meaning": "俘获", "part_of_speech": "verb", "example_chinese": "故事中英雄俘获了反派。"}, {"example": "The tiger was his greatest capture.", "meaning": "捕获物", "part_of_speech": "noun", "example_chinese": "这只老虎是他最大的捕获物。"}]', 'ˈkæp.tʃər', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 14:41:04'),
(7750, 'capture', 'capture sb/sth on camera/film, etc.', '[{"example": "The wildlife photographer captured the eagle''s flight on camera perfectly.", "meaning": "用相机/胶片等拍摄到某人/某物", "part_of_speech": "verb phrase", "example_chinese": "野生动物摄影师完美地用相机拍摄到了老鹰飞行的画面。"}]', '/ˈkæptʃər ɒn ˈkæmərə/', 'B2', 'medium', 'arts and media', '2025-10-20 08:00:00', '2025-10-21 14:41:09'),
(7751, 'carbon', 'carbon', '[{"example": "Diamonds are made of pure carbon.", "meaning": "碳", "part_of_speech": "noun", "example_chinese": "钻石由纯碳构成。"}]', 'ˈkɑː.bən', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 14:41:09'),
(7752, 'carbon dioxide', 'carbon dioxide', '[{"example": "Plants absorb carbon dioxide and release oxygen.", "meaning": "二氧化碳", "part_of_speech": "noun", "example_chinese": "植物吸收二氧化碳并释放氧气。"}]', 'ˌkɑː.bən.dɑɪˈɒk.sɑɪd', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 14:41:10'),
(7753, 'carbon footprint', 'carbon footprint', '[{"example": "Riding a bike reduces your carbon footprint.", "meaning": "碳足迹", "part_of_speech": "noun", "example_chinese": "骑自行车能减少你的碳足迹。"}]', 'ˌkɑː.bənˈfʊt.prɪnt', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 14:41:14'),
(7754, 'carbon monoxide', 'carbon monoxide', '[{"example": "Carbon monoxide is a dangerous gas from car exhaust.", "meaning": "一氧化碳", "part_of_speech": "noun", "example_chinese": "一氧化碳是汽车尾气中的危险气体。"}]', 'ˌkɑː.bən.məˈnɒk.sɑɪd', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 14:41:15'),
(7755, 'cardboard', 'cardboard', '[{"example": "We made a robot costume from cardboard boxes.", "meaning": "硬纸板", "part_of_speech": "noun", "example_chinese": "我们用纸板箱做了个机器人服装。"}]', 'ˈkɑːd.bɔːd', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:41:15'),
(7756, 'cardigan', 'cardigan', '[{"example": "My grandmother knitted me a cozy cardigan for winter.", "meaning": "开襟羊毛衫", "part_of_speech": "noun", "example_chinese": "奶奶给我织了件舒适的冬季开衫。"}]', 'ˈkɑː.dɪ.gən', 'B2', 'medium', 'clothes', '2025-10-20 08:00:00', '2025-10-21 14:41:05'),
(7758, 'care', 'care for sb/sth ', '[{"example": "My grandmother cares for stray cats in her neighborhood.", "meaning": "关心/照顾", "part_of_speech": "verb", "example_chinese": "我奶奶照顾她社区里的流浪猫。"}, {"example": "Would you care for some ice cream?", "meaning": "喜欢", "part_of_speech": "verb", "example_chinese": "你想来点冰淇淋吗？"}]', '/keə(r) fɔː(r)/', 'B2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 14:41:23'),
(7759, 'carelessly', 'carelessly', '[{"example": "He carelessly dropped his ice cream on the ground.", "meaning": "粗心地，马虎地", "part_of_speech": "adverb", "example_chinese": "他不小心把冰淇淋掉在了地上。"}]', 'ˈkeə.ləs.li', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:41:20'),
(7760, 'carelessness', 'carelessness', '[{"example": "His carelessness caused the accident.", "meaning": "粗心，疏忽", "part_of_speech": "noun", "example_chinese": "他的粗心导致了这场事故。"}]', 'ˈkeə.ləs.nəs', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:41:24'),
(7761, 'caring', 'caring', '[{"example": "The caring teacher helped the student after class.", "meaning": "关心他人的，有爱心的", "part_of_speech": "adjective", "example_chinese": "那位有爱心的老师课后帮助了学生。"}]', 'ˈkeə.rɪŋ', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:41:19'),
(7762, 'carnival', 'carnival', '[{"example": "We played games and won prizes at the school carnival.", "meaning": "狂欢节；嘉年华", "part_of_speech": "noun", "example_chinese": "我们在学校嘉年华玩游戏赢得了奖品。"}]', 'ˈkɑr.nɪ.vəl', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:41:30'),
(7766, 'cast', 'cast', '[{"example": "The fisherman cast his net into the river.", "meaning": "投掷", "part_of_speech": "verb", "example_chinese": "渔夫把网撒进河里。"}, {"example": "The movie has a famous cast.", "meaning": "演员表", "part_of_speech": "noun", "example_chinese": "这部电影的演员表很出名。"}, {"example": "He broke his arm and now has a cast.", "meaning": "石膏", "part_of_speech": "noun", "example_chinese": "他手臂骨折了，现在打着石膏。"}]', 'kɑːst', 'B2', 'medium', 'arts and media', '2025-10-20 08:00:00', '2025-10-21 14:41:35'),
(7768, 'casually', 'casually', '[{"example": "He casually mentioned his trip to Paris.", "meaning": "随意地；漫不经心地", "part_of_speech": "adverb", "example_chinese": "他随意地提到了他的巴黎之行。"}]', 'ˈkæʒ.ju.li', 'B2', 'medium', 'clothes, people: personality, work', '2025-10-20 08:00:00', '2025-10-21 14:41:25'),
(7769, 'catalogue', 'catalogue', '[{"example": "I found the book in the library catalogue.", "meaning": "目录", "part_of_speech": "noun", "example_chinese": "我在图书馆目录里找到了这本书。"}]', 'ˈkæt.əl.ɒg', 'B2', 'medium', 'shopping', '2025-10-20 08:00:00', '2025-10-21 14:41:27'),
(7772, 'hold', 'catch/get/grab/take hold of sth/sb ', '[{"example": "The baby grabbed my finger tightly.", "meaning": "抓住/握住", "part_of_speech": "verb", "example_chinese": "宝宝紧紧抓住了我的手指。"}, {"example": "He caught the ball with one hand.", "meaning": "接住", "part_of_speech": "verb", "example_chinese": "他单手接住了球。"}, {"example": "Can you get me a cup of water?", "meaning": "拿取", "part_of_speech": "verb", "example_chinese": "你能给我拿杯水吗？"}, {"example": "Take hold of the rope and don''t let go.", "meaning": "控制住", "part_of_speech": "verb", "example_chinese": "抓住绳子别松手。"}]', '/ɡræb/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 14:41:43'),
(7773, 'catch', 'catch sb''s attention, interest, etc.', '[{"example": "The colorful poster caught my attention immediately.", "meaning": "引起某人的注意/兴趣", "part_of_speech": "verb phrase", "example_chinese": "这张彩色海报立刻引起了我的注意。"}]', '/kætʃ ˈsʌmbədi‿z əˈtenʃən/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 14:41:41'),
(7774, 'catch', 'catch up', '[{"example": "I need to catch up on my homework.", "meaning": "赶上", "part_of_speech": "verb", "example_chinese": "我需要赶作业。"}, {"example": "Let''s have coffee and catch up!", "meaning": "叙旧", "part_of_speech": "verb", "example_chinese": "我们喝咖啡叙叙旧吧！"}]', '/kætʃ ʌp/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 14:41:43'),
(7775, 'catch', 'catch up on/with sth', '[{"example": "I need to catch up on my homework this weekend.", "meaning": "补做；赶上进度", "part_of_speech": "phrasal verb", "example_chinese": "这周末我得补做作业。"}, {"example": "Let''s have coffee so I can catch up with your news.", "meaning": "了解最新情况", "part_of_speech": "phrasal verb", "example_chinese": "我们喝杯咖啡吧，我想听听你的近况。"}]', '/kætʃ ʌp ɒn/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 14:41:50'),
(7776, 'catch', 'catch up (sb) or catch (sb) up', '[{"example": "I ran fast to catch up with my friends.", "meaning": "赶上/追上（某人）", "part_of_speech": "phrasal verb", "example_chinese": "我飞快地跑着去追朋友们。"}, {"example": "Let''s have coffee and catch up!", "meaning": "了解最新情况", "part_of_speech": "phrasal verb", "example_chinese": "我们一起喝咖啡聊聊近况吧！"}]', '/ˈkætʃ ʌp/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 14:41:36');
INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(7777, 'category', 'category', '[{"example": "Books are divided into two categories: fiction and non-fiction.", "meaning": "类别；种类", "part_of_speech": "noun", "example_chinese": "书籍分为两类：小说和非小说类。"}]', 'ˈkæt.ə.gər.i', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:41:48'),
(7778, 'catering', 'catering', '[{"example": "The wedding catering provided delicious food for all the guests.", "meaning": "餐饮服务；酒席承办", "part_of_speech": "noun", "example_chinese": "婚宴餐饮服务为所有宾客提供了美味食物。"}]', 'ˈkeɪ.tər.ɪŋ', 'B2', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 14:42:04'),
(7779, 'cause', 'cause', '[{"example": "The heavy rain was the cause of the flood.", "meaning": "原因；事业", "part_of_speech": "noun", "example_chinese": "大雨是洪水的原因。"}]', 'kɔːz', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:42:09'),
(7781, 'cautious', 'cautious', '[{"example": "The cat was cautious when approaching the new toy.", "meaning": "谨慎的，小心的", "part_of_speech": "adjective", "example_chinese": "猫咪接近新玩具时很谨慎。"}]', 'ˈkɔː.ʃəs', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:41:53'),
(7782, 'cease', 'cease', '[{"example": "The rain will cease by noon.", "meaning": "停止，终止", "part_of_speech": "verb", "example_chinese": "中午前雨会停。"}]', 'siːs', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:41:53'),
(7783, 'cell', 'cell', '[{"example": "The human body has millions of cells.", "meaning": "细胞", "part_of_speech": "noun", "example_chinese": "人体有数百万个细胞。"}, {"example": "The prisoner stayed in a small cell.", "meaning": "牢房", "part_of_speech": "noun", "example_chinese": "囚犯待在一间小牢房里。"}, {"example": "I forgot my cell at home.", "meaning": "手机", "part_of_speech": "noun", "example_chinese": "我把手机忘在家里了。"}]', 'sel', 'B2', 'medium', 'animals', '2025-10-20 08:00:00', '2025-10-21 14:42:00'),
(7785, 'cellar', 'cellar', '[{"example": "We store wine in the cellar.", "meaning": "地下室", "part_of_speech": "noun", "example_chinese": "我们把酒储存在地下室里。"}]', 'ˈsel.ər', 'B2', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 14:41:48'),
(7786, 'cello', 'cello', '[{"example": "She plays the cello beautifully in the orchestra.", "meaning": "大提琴", "part_of_speech": "noun", "example_chinese": "她在管弦乐队中拉大提琴拉得很美。"}]', 'ˈtʃel.əʊ', 'B2', 'medium', 'arts and media', '2025-10-20 08:00:00', '2025-10-21 14:41:58'),
(7787, 'cemetery', 'cemetery', '[{"example": "The old cemetery is surrounded by ancient oak trees.", "meaning": "墓地，公墓", "part_of_speech": "noun", "example_chinese": "这座古老的墓地被年代久远的橡树环绕着。"}]', 'ˈsem.ə.tri', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:41:58'),
(7788, 'centigrade', 'centigrade', '[{"example": "Water boils at 100 degrees centigrade.", "meaning": "摄氏度", "part_of_speech": "noun", "example_chinese": "水在100摄氏度时沸腾。"}]', 'ˈsen.tɪ.greɪd', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 14:42:04'),
(7789, 'certainty', 'certainty', '[{"example": "She spoke with certainty about her future plans.", "meaning": "确定性；确信", "part_of_speech": "noun", "example_chinese": "她对自己的未来计划言之凿凿。"}]', 'ˈsɜː.tən.ti', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 14:42:05'),
