(8728, 'get', 'get the feeling/idea/impression, etc.', '[{"example": "I get the feeling she doesn''t like surprises.", "meaning": "感觉到/意识到/有印象", "part_of_speech": "phrase", "example_chinese": "我感觉她不喜欢惊喜。"}]', '/ɡet ðə ˈfiːlɪŋ/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:00:16'),
