(9331, 'log', 'log off/out', '[{"example": "Please log off when you finish using the computer.", "meaning": "注销/登出", "part_of_speech": "verb", "example_chinese": "用完电脑后请注销登录。"}]', '/lɒɡ ɒf/ /lɒɡ aʊt/', 'B2', 'medium', 'people: actions, technology', '2025-10-20 08:00:00', '2025-10-21 15:15:13'),
(9333, 'long-distance', 'long-distance', '[{"example": "I made a long-distance call to my friend in Australia.", "meaning": "长途的", "part_of_speech": "adjective", "example_chinese": "我给在澳大利亚的朋友打了个长途电话。"}, {"example": "The long-distance was very clear today.", "meaning": "长途电话", "part_of_speech": "noun", "example_chinese": "今天的长途通话非常清晰。"}]', 'ˌlɒŋˈdɪs.tənts', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:15:18'),
(9334, 'long-term', 'long-term', '[{"example": "We need a long-term plan for success.", "meaning": "长期的", "part_of_speech": "adjective", "example_chinese": "我们需要一个长期计划来获得成功。"}]', 'ˌlɒŋˈtɜːm', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:14:22'),
(9337, 'look', 'look as if/as though', '[{"example": "You look as if you''ve seen a ghost!", "meaning": "看起来好像，似乎", "part_of_speech": "phrase", "example_chinese": "你看起来好像见了鬼似的！"}]', '/lʊk æz ɪf/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:14:24'),
(9338, 'look', 'look at sth ', '[{"example": "Look at the cute puppy!", "meaning": "看某物", "part_of_speech": "verb phrase", "example_chinese": "看那只可爱的小狗！"}]', '/lʊk æt/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:14:23'),
(9341, 'look', 'look back', '[{"example": "When I look back on my childhood, I feel happy.", "meaning": "回顾，回忆", "part_of_speech": "phrasal verb", "example_chinese": "当我回顾童年时，我感到快乐。"}]', '/lʊk bæk/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:15:07'),
(9342, 'look', 'look down on sb', '[{"example": "Don''t look down on him just because he''s different.", "meaning": "看不起某人", "part_of_speech": "phrasal verb", "example_chinese": "不要仅仅因为他与众不同就看不起他。"}]', '/lʊk daʊn ɒn ˈsʌmbədi/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:16:55'),
(9344, 'look', 'look into sth ', '[{"example": "The police will look into the strange noise.", "meaning": "调查；研究", "part_of_speech": "verb", "example_chinese": "警察会调查这个奇怪的声音。"}, {"example": "Can you look into this book for me?", "meaning": "浏览；快速查看", "part_of_speech": "verb", "example_chinese": "你能帮我快速看一下这本书吗？"}]', '/lʊk ˈɪntuː/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:23:58'),
(9345, 'look', 'look out for sb/sth', '[{"example": "Look out for your little sister at the playground.", "meaning": "留意/照顾", "part_of_speech": "phrasal verb", "example_chinese": "在游乐场要照顾好你妹妹。"}, {"example": "Look out for icy patches on the road!", "meaning": "小心提防", "part_of_speech": "phrasal verb", "example_chinese": "小心路上的冰面！"}]', '/lʊk aʊt fɔːr/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:12:48'),
(9346, 'eye', 'look sb in the eye/eyes', '[{"example": "He couldn''t look me in the eye when he lied.", "meaning": "直视某人", "part_of_speech": "phrase", "example_chinese": "他撒谎时不敢直视我的眼睛。"}]', '/lʊk ˌsʌmbɒdi ɪn ði aɪ/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:12:46'),
(9347, 'look', 'look through sth', '[{"example": "I''ll quickly look through my notes before the meeting.", "meaning": "快速查看；浏览", "part_of_speech": "phrasal verb", "example_chinese": "开会前我会快速浏览一下笔记。"}, {"example": "The detective looked through all the evidence carefully.", "meaning": "仔细检查", "part_of_speech": "phrasal verb", "example_chinese": "侦探仔细检查了所有证据。"}]', '/lʊk θruː/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:12:50'),
(9348, 'look', 'look up to sb', '[{"example": "Children often look up to their teachers.", "meaning": "钦佩；尊敬", "part_of_speech": "phrasal verb", "example_chinese": "孩子们常常钦佩他们的老师。"}]', '/lʊk ʌp tuː/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:12:50'),
(9351, 'lose', 'lose interest/patience, etc.', '[{"example": "The child quickly lost interest in the new toy.", "meaning": "失去兴趣/耐心等", "part_of_speech": "verb", "example_chinese": "孩子很快对新玩具失去了兴趣。"}, {"example": "The teacher lost patience with the noisy class.", "meaning": "失去耐心", "part_of_speech": "verb", "example_chinese": "老师对吵闹的班级失去了耐心。"}]', '/luːz ˈɪntrəst/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:12:55'),
(9352, 'lose', 'lose touch', '[{"example": "We lost touch after college.", "meaning": "失去联系", "part_of_speech": "verb phrase", "example_chinese": "大学毕业后我们就失去了联系。"}]', '/luːz tʌtʃ/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:12:55'),
(9354, 'lose', 'lose track', '[{"example": "I lost track of time while playing games.", "meaning": "忘记；失去联系", "part_of_speech": "verb phrase", "example_chinese": "我玩游戏时忘了时间。"}]', '/luːz træk/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:12:56'),
(9356, 'lose', 'lose your life', '[{"example": "He almost lost his life in the car accident.", "meaning": "丧生；失去生命", "part_of_speech": "verb_phrase", "example_chinese": "他差点在车祸中丧生。"}]', '/luːz jɔːr laɪf/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:00'),
(9357, 'lose', 'lose your temper', '[{"example": "Dad lost his temper when I broke the window.", "meaning": "发脾气", "part_of_speech": "verb phrase", "example_chinese": "我打碎窗户时爸爸发脾气了。"}]', '/luːz jɔːr ˈtempər/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:13:01'),
(9359, 'lose', 'lose your voice', '[{"example": "After cheering at the concert, I lost my voice for two days!", "meaning": "失声；说不出话", "part_of_speech": "verb phrase", "example_chinese": "在音乐会上欢呼后，我失声了两天！"}]', '/luːz jɔː(r) vɔɪs/', 'B2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 15:13:02'),
(9361, 'loss', 'loss', '[{"example": "The loss of his favorite toy made him sad.", "meaning": "损失；丧失", "part_of_speech": "noun", "example_chinese": "失去心爱的玩具让他很难过。"}, {"example": "Our team''s loss in the game was disappointing.", "meaning": "失败；输掉", "part_of_speech": "noun", "example_chinese": "我们队在比赛中失利令人失望。"}]', 'lɒs', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:08'),
(9366, 'lower', 'lower', '[{"example": "Please lower your voice in the library.", "meaning": "降低，减少", "part_of_speech": "verb", "example_chinese": "请在图书馆里降低音量。"}, {"example": "The lower shelf is for children''s books.", "meaning": "较低的，下层的", "part_of_speech": "adjective", "example_chinese": "下层书架是放儿童书籍的。"}]', 'ˈləʊ.ər', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:09'),
(9368, 'loyal', 'loyal', '[{"example": "My dog is very loyal to our family.", "meaning": "忠诚的，忠心的", "part_of_speech": "adjective", "example_chinese": "我的狗对我们家非常忠诚。"}]', 'ˈlɔɪ.əl', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:13:07'),
(9369, 'loyalty', 'loyalty', '[{"example": "Dogs are known for their loyalty to their owners.", "meaning": "忠诚", "part_of_speech": "noun", "example_chinese": "狗以对主人的忠诚而闻名。"}]', 'ˈlɔɪ.əl.ti', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:13:11'),
(9371, 'lung', 'lung', '[{"example": "Smoking can damage your lungs.", "meaning": "肺", "part_of_speech": "noun", "example_chinese": "吸烟会损害你的肺。"}]', 'lʌŋ', 'B2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 15:13:12'),
(9373, 'lyrics', 'lyrics', '[{"example": "I love the lyrics of this song because they tell a beautiful story.", "meaning": "歌词", "part_of_speech": "noun", "example_chinese": "我喜欢这首歌的歌词，因为它们讲述了一个美丽的故事。"}]', 'ˈlɪr.ɪks', 'B2', 'medium', 'arts and media', '2025-10-20 08:00:00', '2025-10-21 15:13:14'),
(9375, 'magical', 'magical', '[{"example": "The fireworks created a magical display in the night sky.", "meaning": "神奇的，魔法的", "part_of_speech": "adjective", "example_chinese": "烟花在夜空中创造了神奇的景象。"}]', 'ˈmædʒ.ɪ.kəl', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:17'),
(9377, 'maintain', 'maintain', '[{"example": "We must maintain our friendship forever.", "meaning": "维持，保持", "part_of_speech": "verb", "example_chinese": "我们必须永远保持友谊。"}, {"example": "He maintains his bicycle every month.", "meaning": "维护，保养", "part_of_speech": "verb", "example_chinese": "他每月保养他的自行车。"}, {"example": "She maintains that she is right.", "meaning": "坚持主张", "part_of_speech": "verb", "example_chinese": "她坚持认为自己是对的。"}]', 'meɪnˈteɪn', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:21'),
(9379, 'maintenance', 'maintenance', '[{"example": "Regular maintenance keeps the car running smoothly.", "meaning": "维护，保养", "part_of_speech": "noun", "example_chinese": "定期保养让汽车平稳运行。"}]', 'ˈmeɪn.tə.nənts', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:19'),
(9380, 'major', 'major', '[{"example": "Her major is computer science.", "meaning": "主修专业；少校", "part_of_speech": "noun", "example_chinese": "她的主修专业是计算机科学。"}]', 'ˈmeɪ.dʒər', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:21'),
(9381, 'majority', 'majority', '[{"example": "The majority of students prefer pizza over salad.", "meaning": "大多数，大部分", "part_of_speech": "noun", "example_chinese": "大多数学生更喜欢披萨而不是沙拉。"}]', 'məˈdʒɒr.ə.ti', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:13:24'),
(9383, 'difference', 'make a (big) difference', '[{"example": "Your help made a big difference in my project.", "meaning": "产生（重大）影响/起重要作用", "part_of_speech": "phrase", "example_chinese": "你的帮助对我的项目产生了重大影响。"}]', '/meɪk ə (bɪɡ) ˈdɪfərəns/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:26'),
(9385, 'fool', 'make a fool of yourself ', '[{"example": "He made a fool of himself by dancing on the table.", "meaning": "出丑，闹笑话", "part_of_speech": "verb phrase", "example_chinese": "他在桌子上跳舞，出了洋相。"}]', '/meɪk ə fuːl ɒv jɔːˈself/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:13:26'),
(9387, 'fool', 'make a fool (out) of sb ', '[{"example": "He made a fool of me in front of the whole class with his trick.", "meaning": "愚弄某人，让某人出丑", "part_of_speech": "verb phrase", "example_chinese": "他的恶作剧让我在全班面前出丑了。"}]', '/meɪk ə fuːl əv ˈsʌmbədi/', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:13:30'),
(9389, 'make', 'make for sth', '[{"example": "Let''s make for the exit before the crowd gets bigger.", "meaning": "前往；导致；有利于", "part_of_speech": "phrasal verb", "example_chinese": "我们趁人还不多时往出口走吧。"}, {"example": "Regular exercise makes for better health.", "meaning": "有助于促成", "part_of_speech": "phrasal verb", "example_chinese": "定期锻炼有助于健康。"}]', '/meɪk fɔː(r)/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:33'),
(9390, 'fun', 'make fun of sb/sth', '[{"example": "The children made fun of his new haircut.", "meaning": "取笑；嘲弄", "part_of_speech": "verb", "example_chinese": "孩子们取笑他的新发型。"}]', '/meɪk fʌn ɒv/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:31'),
(9392, 'difference', 'make no difference/not make any difference', '[{"example": "Eating ice cream before the race made no difference to my speed.", "meaning": "没有影响/无关紧要", "part_of_speech": "phrase", "example_chinese": "赛前吃冰淇淋对我的速度没有影响。"}]', '/meɪk nəʊ ˈdɪf.ər.əns/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:35');
INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(9393, 'make', 'make out sth/sb or make sth/sb out', '[{"example": "I can''t make out his handwriting in the dark.", "meaning": "辨认出", "part_of_speech": "phrasal verb", "example_chinese": "我在黑暗中辨认不出他的笔迹。"}, {"example": "It''s hard to make out what she wants.", "meaning": "理解", "part_of_speech": "phrasal verb", "example_chinese": "很难理解她想要什么。"}, {"example": "He made out that he was an expert.", "meaning": "声称", "part_of_speech": "phrasal verb", "example_chinese": "他声称自己是专家。"}]', '/meɪk aʊt/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:41'),
(9394, 'maker', 'maker', '[{"example": "My little brother is a great cookie maker.", "meaning": "制造者；创造者", "part_of_speech": "noun", "example_chinese": "我的弟弟是个很棒的饼干制作师。"}]', 'ˈmeɪ.kər', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:12:43'),
(9395, 'make', 'make sense', '[{"example": "Your explanation doesn''t make sense.", "meaning": "有意义；讲得通", "part_of_speech": "verb phrase", "example_chinese": "你的解释说不通。"}, {"example": "It makes sense to save money for the future.", "meaning": "明智的；合理的", "part_of_speech": "verb phrase", "example_chinese": "为未来存钱是明智的。"}]', '/meɪk sens/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:43'),
(9399, 'make', 'make sth into sth ', '[{"example": "We can make this old shirt into a cute bag.", "meaning": "把某物改造成另一物", "part_of_speech": "verb", "example_chinese": "我们可以把这件旧衬衫改造成一个可爱的包。"}]', '/meɪk ˈsʌmθɪŋ ˈɪntə ˈsʌmθɪŋ/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:43'),
(9400, 'best', 'make the best of sth', '[{"example": "Even though it rained, we made the best of our picnic by playing games in the car.", "meaning": "充分利用；尽力做好", "part_of_speech": "verb phrase", "example_chinese": "尽管下雨了，我们在车里玩游戏，充分利用了这次野餐。"}]', '/meɪk ðə best əv/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:47'),
(9402, 'make', 'make the most of sth', '[{"example": "Let''s make the most of this sunny day and go hiking!", "meaning": "充分利用", "part_of_speech": "verb phrase", "example_chinese": "让我们充分利用这个阳光明媚的日子去远足吧！"}]', '/meɪk ðə məʊst əv/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:13:47'),
(9404, 'make', 'make the/sb''s bed', '[{"example": "I make my bed every morning after waking up.", "meaning": "铺床", "part_of_speech": "verb_phrase", "example_chinese": "我每天醒来后都会铺床。"}]', '/meɪk ðə bed/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:48'),
(9405, 'make', 'make up for sth ', '[{"example": "I bought her flowers to make up for forgetting her birthday.", "meaning": "补偿/弥补", "part_of_speech": "phrasal verb", "example_chinese": "我买了花来弥补忘记她生日的过错。"}]', '/meɪk ʌp fɔː(r)/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:52'),
(9406, 'make', 'make up sth or make sth up', '[{"example": "He made up a funny story about a talking cat.", "meaning": "编造；虚构", "part_of_speech": "phrasal verb", "example_chinese": "他编了一个关于会说话的猫的有趣故事。"}, {"example": "She will make up the test next week.", "meaning": "补考；弥补", "part_of_speech": "phrasal verb", "example_chinese": "她将在下周补考。"}, {"example": "They argued but made up quickly.", "meaning": "和好；和解", "part_of_speech": "phrasal verb", "example_chinese": "他们吵了架但很快和好了。"}]', '/meɪk ʌp/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:13:57'),
(9407, 'use', 'make use of sth', '[{"example": "We should make use of old boxes to build a castle.", "meaning": "利用某物", "part_of_speech": "verb phrase", "example_chinese": "我们应该利用旧盒子搭个城堡。"}]', '/meɪk juːz ɒv/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:13:53'),
(9408, 'way', 'make your way', '[{"example": "We made our way through the crowded market.", "meaning": "前往/前进", "part_of_speech": "verb phrase", "example_chinese": "我们穿过拥挤的市场向前走。"}, {"example": "She worked hard to make her way in the business world.", "meaning": "取得成功", "part_of_speech": "verb phrase", "example_chinese": "她努力工作，在商界取得了成功。"}]', '/meɪk jɔːr weɪ/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:14:00'),
(9411, 'management', 'management', '[{"example": "Good time management helps you work efficiently.", "meaning": "管理；经营", "part_of_speech": "noun", "example_chinese": "良好的时间管理帮助你高效工作。"}]', 'ˈmæn.ɪdʒ.mənt', 'B2', 'medium', 'work', '2025-10-20 08:00:00', '2025-10-21 15:13:58'),
(9412, 'mankind', 'mankind', '[{"example": "Mankind has achieved amazing things in space exploration.", "meaning": "人类", "part_of_speech": "noun", "example_chinese": "人类在太空探索中取得了惊人成就。"}]', 'mænˈkaɪnd', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:14:02'),
