(11000, 'tragedy', 'tragedy', '[{"example": "The sudden loss of the great scientist was a tragedy for the whole world.", "meaning": "悲剧；灾难", "part_of_speech": "noun", "example_chinese": "这位伟大科学家的突然离世对全世界来说是一场悲剧。"}]', 'ˈtrædʒ.ə.di', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:46:12'),
