(11002, 'trail', 'trail', '[{"example": "We hiked along a narrow trail in the forest.", "meaning": "小径", "part_of_speech": "noun", "example_chinese": "我们沿着森林里一条狭窄的小径徒步。"}, {"example": "The car left a trail of dust on the road.", "meaning": "痕迹", "part_of_speech": "noun", "example_chinese": "汽车在路上留下了一道灰尘痕迹。"}]', 'treɪl', 'B2', 'medium', 'travel', '2025-10-20 08:00:00', '2025-10-21 15:46:17'),
(11007, 'transform', 'transform', '[{"example": "The caterpillar will transform into a butterfly.", "meaning": "改变；转换", "part_of_speech": "verb", "example_chinese": "毛毛虫会变成蝴蝶。"}]', 'trænsˈfɔːm', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:46:17'),
(11008, 'transitive', 'transitive', '[{"example": "The verb ''eat'' is transitive in ''She eats an apple''.", "meaning": "及物的", "part_of_speech": "adjective", "example_chinese": "在''她吃苹果''中，动词''吃''是及物的。"}]', 'ˈtræn.zə.tɪv', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:46:22'),
(11009, 'transparent', 'transparent', '[{"example": "The glass is transparent.", "meaning": "透明的", "part_of_speech": "adjective", "example_chinese": "玻璃是透明的。"}, {"example": "Her lie was transparent to everyone.", "meaning": "明显的", "part_of_speech": "adjective", "example_chinese": "她的谎言对每个人都很明显。"}, {"example": "He was transparent about his feelings.", "meaning": "坦率的", "part_of_speech": "adjective", "example_chinese": "他对自己的感受很坦率。"}]', 'trænˈspær.ənt', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:46:28'),
(11012, 'trap', 'trap', '[{"example": "The mouse was caught in the trap.", "meaning": "陷阱", "part_of_speech": "noun", "example_chinese": "老鼠掉进了陷阱。"}, {"example": "The car was trapped in the mud.", "meaning": "困住", "part_of_speech": "verb", "example_chinese": "汽车陷在泥里了。"}, {"example": "It''s a clever trap to catch the thief.", "meaning": "圈套", "part_of_speech": "noun", "example_chinese": "这是个抓小偷的巧妙圈套。"}]', 'træp', 'B2', 'medium', 'animals', '2025-10-20 08:00:00', '2025-10-21 15:46:31'),
(11014, 'tray', 'tray', '[{"example": "The waiter carried drinks on a shiny silver tray.", "meaning": "托盘；盘子", "part_of_speech": "noun", "example_chinese": "服务员用闪亮的银托盘端着饮料。"}]', 'treɪ', 'B2', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 15:46:29'),
(11015, 'treasure', 'treasure', '[{"example": "The pirates found a treasure chest on the island.", "meaning": "宝藏；珍宝", "part_of_speech": "noun", "example_chinese": "海盗在岛上发现了一个宝藏箱。"}, {"example": "I treasure the memories of our trip together.", "meaning": "珍爱；珍藏", "part_of_speech": "verb", "example_chinese": "我珍视我们一起旅行的回忆。"}]', 'ˈtreʒ.ər', 'B2', 'medium', 'money', '2025-10-20 08:00:00', '2025-10-21 15:46:24'),
(11016, 'treat', 'treat', '[{"example": "My mom will treat us to ice cream.", "meaning": "对待；治疗；款待", "part_of_speech": "verb", "example_chinese": "妈妈要请我们吃冰淇淋。"}, {"example": "The puppy got a treat for sitting.", "meaning": "款待；乐趣", "part_of_speech": "noun", "example_chinese": "小狗因乖乖坐下得到了奖励。"}]', 'triːt', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:46:36'),
(11020, 'treatment', 'treatment', '[{"example": "The new treatment cured his illness quickly.", "meaning": "治疗", "part_of_speech": "noun", "example_chinese": "新疗法很快治好了他的病。"}, {"example": "The kind treatment made her feel welcome.", "meaning": "对待", "part_of_speech": "noun", "example_chinese": "友好的对待让她感到受欢迎。"}, {"example": "The water treatment makes it safe to drink.", "meaning": "处理", "part_of_speech": "noun", "example_chinese": "水处理使其可以安全饮用。"}]', 'ˈtriːt.mənt', 'B2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 15:46:38'),
(11022, 'trekking', 'trekking', '[{"example": "We went trekking in the mountains last summer.", "meaning": "长途徒步旅行", "part_of_speech": "noun", "example_chinese": "去年夏天我们去山里进行了长途徒步。"}]', 'ˈtrek.ɪŋ', 'B2', 'medium', 'travel', '2025-10-20 08:00:00', '2025-10-21 15:46:41'),
(11023, 'tremble', 'tremble', '[{"example": "The puppy trembles during the thunderstorm.", "meaning": "颤抖，发抖", "part_of_speech": "verb", "example_chinese": "小狗在雷雨中瑟瑟发抖。"}]', 'ˈtrem.bl ̩', 'B2', 'medium', 'people: actions, people: personality', '2025-10-20 08:00:00', '2025-10-21 15:46:36'),
(11024, 'tremendous', 'tremendous', '[{"example": "The elephant made a tremendous splash in the pool.", "meaning": "巨大的；极好的", "part_of_speech": "adjective", "example_chinese": "大象在泳池里溅起了巨大的水花。"}]', 'trɪˈmen.dəs', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:46:43'),
(11026, 'tremendously', 'tremendously', '[{"example": "The new policy helped the company grow tremendously.", "meaning": "极大地；非常地", "part_of_speech": "adverb", "example_chinese": "新政策极大地促进了公司的发展。"}]', 'trɪˈmen.də.sli', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:46:41'),
(11027, 'trial', 'trial', '[{"example": "The trial will begin next Monday.", "meaning": "审判", "part_of_speech": "noun", "example_chinese": "审判将于下周一开庭。"}, {"example": "You can download a free trial of the software.", "meaning": "试用", "part_of_speech": "noun", "example_chinese": "你可以下载软件的免费试用版。"}, {"example": "The drug is still in clinical trials.", "meaning": "试验", "part_of_speech": "noun", "example_chinese": "这种药物仍在临床试验阶段。"}]', 'traɪəl', 'B2', 'medium', 'crime', '2025-10-20 08:00:00', '2025-10-21 15:46:55'),
(11028, 'triangle', 'triangle', '[{"example": "A triangle has three sides and three angles.", "meaning": "三角形", "part_of_speech": "noun", "example_chinese": "三角形有三条边和三个角。"}]', 'ˈtraɪ.æŋ.gl ̩', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:46:46'),
(11029, 'tribe', 'tribe', '[{"example": "The tribe gathered around the fire for storytelling.", "meaning": "部落", "part_of_speech": "noun", "example_chinese": "部落成员围坐在篝火旁听故事。"}]', 'traɪb', 'B2', 'medium', 'relationships', '2025-10-20 08:00:00', '2025-10-21 15:46:46'),
(11032, 'tricky', 'tricky', '[{"example": "The magician''s trick was very tricky to figure out.", "meaning": "狡猾的；棘手的", "part_of_speech": "adjective", "example_chinese": "魔术师的把戏很难看穿"}, {"example": "Solving this puzzle requires tricky thinking.", "meaning": "巧妙的；需要技巧的", "part_of_speech": "adjective", "example_chinese": "解开这个谜题需要巧妙的思维"}]', 'ˈtrɪk.i', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:46:50'),
(11034, 'trivial', 'trivial', '[{"example": "Don''t waste time on trivial matters.", "meaning": "琐碎的，不重要的", "part_of_speech": "adjective", "example_chinese": "不要在琐事上浪费时间。"}]', 'ˈtrɪv.i.əl', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:46:51'),
(11035, 'trolley', 'trolley', '[{"example": "We need a trolley to carry these groceries.", "meaning": "手推车", "part_of_speech": "noun", "example_chinese": "我们需要一辆手推车来运这些杂货。"}, {"example": "The old trolley clanged along the city streets.", "meaning": "电车", "part_of_speech": "noun", "example_chinese": "老电车沿着城市街道叮当作响地行驶。"}]', 'ˈtrɒl.i', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:46:59'),
(11036, 'trophy', 'trophy', '[{"example": "He proudly displayed his tennis trophy on the shelf.", "meaning": "奖杯，战利品", "part_of_speech": "noun", "example_chinese": "他骄傲地把网球奖杯陈列在架子上。"}]', 'ˈtrəʊ.fi', 'B2', 'medium', 'shopping', '2025-10-20 08:00:00', '2025-10-21 15:47:01'),
(11037, 'tropical', 'tropical', '[{"example": "Pineapples grow in tropical climates.", "meaning": "热带的", "part_of_speech": "adjective", "example_chinese": "菠萝生长在热带气候中。"}, {"example": "The party had a tropical atmosphere with colorful decorations.", "meaning": "热情的", "part_of_speech": "adjective", "example_chinese": "派对有着色彩缤纷的装饰，充满热情的氛围。"}]', 'ˈtrɒp.ɪ.kəl', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 15:47:07'),
(11041, 'truly', 'truly', '[{"example": "I truly believe in your dream.", "meaning": "真正地，确实", "part_of_speech": "adverb", "example_chinese": "我真心相信你的梦想。"}]', 'ˈtruː.li', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:04'),
(11042, 'trunk', 'trunk', '[{"example": "The squirrel ran up the tree trunk.", "meaning": "树干", "part_of_speech": "noun", "example_chinese": "松鼠沿着树干跑了上去。"}, {"example": "We put the luggage in the trunk of the car.", "meaning": "汽车后备箱", "part_of_speech": "noun", "example_chinese": "我们把行李放在汽车后备箱里。"}, {"example": "The elephant used its trunk to drink water.", "meaning": "象鼻", "part_of_speech": "noun", "example_chinese": "大象用鼻子喝水。"}]', 'trʌŋk', 'B2', 'medium', 'natural world', '2025-10-20 08:00:00', '2025-10-21 15:46:59'),
(11044, 'truth', 'truth', '[{"example": "The detective finally discovered the truth.", "meaning": "真相，事实", "part_of_speech": "noun", "example_chinese": "侦探终于发现了真相。"}]', 'truːθ', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:09'),
(11046, 'try', 'try out sth or try sth out', '[{"example": "I want to try out my new bike in the park.", "meaning": "试用；试验", "part_of_speech": "phrasal verb", "example_chinese": "我想在公园里试试我的新自行车。"}]', '/traɪ aʊt/', 'B2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 15:47:12'),
(11050, 'turn', 'turn blue/cold/nasty, etc.', '[{"example": "When he heard the news, his face turned blue with shock.", "meaning": "脸色发青/态度变冷/情况变糟", "part_of_speech": "verb_phrase", "example_chinese": "听到消息时，他震惊得脸色发青。"}, {"example": "The weather turned cold suddenly in the afternoon.", "meaning": "（天气）变冷", "part_of_speech": "verb_phrase", "example_chinese": "下午天气突然变冷了。"}, {"example": "Her mood turned nasty after the argument.", "meaning": "变得恶劣", "part_of_speech": "verb_phrase", "example_chinese": "争吵后她的心情变得很恶劣。"}]', '/tɜːn bluː/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:11'),
(11051, 'turn', 'turn down sb/sth or turn sb/sth down ', '[{"example": "She had to turn down the job offer because of the low salary.", "meaning": "拒绝", "part_of_speech": "phrasal verb", "example_chinese": "因为薪水太低，她不得不拒绝这份工作邀请。"}, {"example": "Please turn down the TV, I''m trying to study.", "meaning": "调低（音量/亮度）", "part_of_speech": "phrasal verb", "example_chinese": "请把电视音量调低，我正在学习。"}]', '/tɜːn daʊn/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:47:19'),
(11052, 'turn', 'turn out', '[{"example": "The weather turned out to be sunny.", "meaning": "结果是，证明是", "part_of_speech": "verb", "example_chinese": "结果天气是晴朗的。"}, {"example": "The factory turns out 100 cars a day.", "meaning": "生产，制造", "part_of_speech": "verb", "example_chinese": "这家工厂每天生产100辆汽车。"}, {"example": "Many people turned out for the concert.", "meaning": "出席，参加", "part_of_speech": "verb", "example_chinese": "很多人出席了音乐会。"}]', '/tɜːn aʊt/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:19'),
(11055, 'turn', 'turn (sth) back', '[{"example": "The police turned back the protesters at the gate.", "meaning": "使原路返回/阻止前进", "part_of_speech": "verb", "example_chinese": "警察在大门口拦住了抗议者。"}, {"example": "She turned back to page 50 to review the answer.", "meaning": "翻回（书页）", "part_of_speech": "verb", "example_chinese": "她翻回第50页复习答案。"}]', '/tɜːn bæk/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:20'),
(11056, 'turn', 'turn to sb/sth ', '[{"example": "When I have problems, I always turn to my best friend.", "meaning": "向...求助/转向", "part_of_speech": "verb", "example_chinese": "遇到问题时，我总是向我最好的朋友求助。"}]', '/tɜːn tuː/', 'B2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 15:47:25'),
(11057, 'turn', 'turn up (somewhere) ', '[{"example": "He finally turned up at the party an hour late.", "meaning": "出现；到达", "part_of_speech": "phrasal verb", "example_chinese": "他终于在派对开始一小时后出现了。"}]', '/tɜːn ʌp/', 'B2', 'medium', 'people: actions, travel', '2025-10-20 08:00:00', '2025-10-21 15:47:23'),
(11058, 'tutor', 'tutor', '[{"example": "My math tutor helps me with homework every Wednesday.", "meaning": "家庭教师；导师", "part_of_speech": "noun", "example_chinese": "我的数学家教每周三帮我辅导作业。"}, {"example": "She tutors children in English after school.", "meaning": "辅导；教导", "part_of_speech": "verb", "example_chinese": "她放学后给孩子们辅导英语。"}]', 'ˈtjuː.tər', 'B2', 'medium', 'education, work', '2025-10-20 08:00:00', '2025-10-21 15:47:30'),
(11059, 'twisted', 'twisted', '[{"example": "The tree had twisted branches after the storm.", "meaning": "扭曲的；不正常的", "part_of_speech": "adjective", "example_chinese": "暴风雨后，这棵树的树枝变得扭曲了。"}, {"example": "She twisted the cap off the bottle easily.", "meaning": "扭动；曲解", "part_of_speech": "verb", "example_chinese": "她轻松地扭开了瓶盖。"}]', 'ˈtwɪs.tɪd', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:47:27'),
(11061, 'ultimate', 'ultimate', '[{"example": "Winning the championship is our ultimate goal.", "meaning": "最终的，极端的，根本的", "part_of_speech": "adjective", "example_chinese": "赢得冠军是我们的最终目标。"}, {"example": "This car is the ultimate in luxury.", "meaning": "终极事物，最好/最先进的事物", "part_of_speech": "noun", "example_chinese": "这辆车是豪华的终极体现。"}]', 'ˈʌl.tɪ.mət', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:35'),
(11062, 'unacceptable', 'unacceptable', '[{"example": "His rude behavior is unacceptable.", "meaning": "不可接受的", "part_of_speech": "adjective", "example_chinese": "他粗鲁的行为是不可接受的。"}]', 'ˌʌn.ækˈsep.tə.bl ̩', 'B2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 15:47:34'),
(11063, 'unattractive', 'unattractive', '[{"example": "The old house was unattractive but very cozy.", "meaning": "无吸引力的，不漂亮的", "part_of_speech": "adjective", "example_chinese": "这栋老房子不漂亮但很舒适。"}]', 'ˌʌn.əˈtræk.tɪv', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:30'),
(11064, 'unavailable', 'unavailable', '[{"example": "The manager is unavailable until Monday.", "meaning": "不可用的；无法获得的", "part_of_speech": "adjective", "example_chinese": "经理周一前都没空。"}]', 'ʌn.əˈveɪ.lə.bl ̩', 'B2', 'medium', 'shopping', '2025-10-20 08:00:00', '2025-10-21 15:47:39'),
(11065, 'unaware', 'unaware', '[{"example": "The cat was unaware of the dog behind it.", "meaning": "未察觉的；不知道的", "part_of_speech": "adjective", "example_chinese": "这只猫没注意到身后的狗。"}]', 'ˌʌn.əˈweər', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:47:36'),
(11066, 'unbearable', 'unbearable', '[{"example": "The heat in this room is unbearable.", "meaning": "难以忍受的", "part_of_speech": "adjective", "example_chinese": "这个房间的热度让人难以忍受。"}]', 'ʌnˈbeə.rə.bl ̩', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:40'),
(11068, 'uncertain', 'uncertain', '[{"example": "The weather is uncertain for our picnic tomorrow.", "meaning": "不确定的；犹豫的", "part_of_speech": "adjective", "example_chinese": "我们明天野餐的天气还不确定。"}]', 'ʌnˈsɜː.tən', 'B2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 15:47:41'),
(11070, 'unchanged', 'unchanged', '[{"example": "The price remained unchanged for three years.", "meaning": "未改变的", "part_of_speech": "adjective", "example_chinese": "这个价格三年都保持不变。"}]', 'ʌnˈtʃeɪndʒd', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:44'),
(11071, 'unclear', 'unclear', '[{"example": "The instructions were unclear, so I made a mistake.", "meaning": "不清楚的；模糊的", "part_of_speech": "adjective", "example_chinese": "说明不清楚，所以我犯了个错误。"}]', 'ʌnˈklɪər', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:46');
INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(11072, 'unconscious', 'unconscious', '[{"example": "The boxer was unconscious for three minutes after the punch.", "meaning": "无意识的；失去知觉的", "part_of_speech": "adjective", "example_chinese": "拳击手被击打后昏迷了三分钟。"}, {"example": "Freud studied the human unconscious deeply.", "meaning": "潜意识", "part_of_speech": "noun", "example_chinese": "弗洛伊德深入研究了人类的潜意识。"}]', 'ʌnˈkɒn.tʃəs', 'B2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 15:47:51'),
(11074, 'under', 'under attack/control/investigation, etc.', '[{"example": "The castle is under attack by dragons!", "meaning": "遭受攻击/处于控制下/接受调查（等）", "part_of_speech": "phrase", "example_chinese": "城堡正遭受巨龙的攻击！"}, {"example": "The robot is under control now.", "meaning": "被控制", "part_of_speech": "phrase", "example_chinese": "机器人现在被控制住了。"}, {"example": "The mystery is under investigation.", "meaning": "接受调查", "part_of_speech": "phrase", "example_chinese": "这个谜案正在调查中。"}]', '/ˈʌndər əˈtæk/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:49'),
(11075, 'control', 'under control', '[{"example": "Don''t worry, the fire is under control now.", "meaning": "处于控制之下；情况稳定", "part_of_speech": "adjective", "example_chinese": "别担心，火势现在已经得到控制了。"}]', '/ˌʌndə kənˈtrəʊl/', 'B2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 15:47:51'),
