(16505, 'hope', 'in the hope of/that', '[{"example": "She studied hard in the hope of passing the exam.", "meaning": "怀着...的希望", "part_of_speech": "prepositional_phrase", "example_chinese": "她努力学习，希望能通过考试。"}, {"example": "He waited in the hope that she would come back.", "meaning": "希望...", "part_of_speech": "conjunctional_phrase", "example_chinese": "他等待着，希望她会回来。"}]', '/ɪn ðə həʊp ɒv/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:14:55'),
