(16511, 'same', 'in the same way', '[{"example": "Birds learn to fly in the same way babies learn to walk.", "meaning": "同样地", "part_of_speech": "adverb", "example_chinese": "鸟儿学飞就像婴儿学走路一样。"}]', '/ɪn ðə seɪm weɪ/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:14:54'),
