(16523, 'invaluable', 'invaluable', '[{"example": "Her advice was invaluable for my career.", "meaning": "极其宝贵的", "part_of_speech": "adjective", "example_chinese": "她的建议对我的职业生涯非常宝贵。"}]', 'ɪnˈvæl.ju.ə.bl ̩', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:14:57'),
