(16537, 'appear', 'it would appear (that)', '[{"example": "It would appear that the cat has stolen my sandwich.", "meaning": "看起来似乎", "part_of_speech": "phrase", "example_chinese": "看起来这只猫偷了我的三明治。"}]', '/ɪt wʊd əˈpɪə(r) ðæt/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:15:09'),
