(16701, 'mechanism', 'mechanism', '[{"example": "The clock''s mechanism is made of brass.", "meaning": "机械装置；机制", "part_of_speech": "noun", "example_chinese": "这个钟表的机械装置是黄铜制成的。"}]', 'ˈmek.ə.nɪz.əm', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:17:55'),
(16705, 'memo', 'memo', '[{"example": "I left a memo on your desk about the meeting.", "meaning": "备忘录", "part_of_speech": "noun", "example_chinese": "我在你桌上留了关于会议的备忘录。"}]', 'ˈmem.əʊ', 'C1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 16:18:00'),
