(16707, 'merit', 'merit', '[{"example": "Hard work has its own merit.", "meaning": "优点；价值；功绩", "part_of_speech": "noun", "example_chinese": "努力本身就有价值。"}]', 'ˈmer.ɪt', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:05'),
(16708, 'mess', 'mess about/around', '[{"example": "Stop messing about and do your homework!", "meaning": "胡闹/浪费时间", "part_of_speech": "verb", "example_chinese": "别胡闹了，快做作业！"}, {"example": "He spent the afternoon messing around with his bike.", "meaning": "摆弄/瞎搞", "part_of_speech": "verb", "example_chinese": "他花了一下午瞎摆弄他的自行车。"}]', '/mes əˈbaʊt/', 'C1', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 16:18:06'),
(16711, 'middle-class', 'middle-class', '[{"example": "The middle-class often values education and stability.", "meaning": "中产阶级", "part_of_speech": "noun", "example_chinese": "中产阶级通常重视教育和稳定。"}]', 'ˌmɪd.l ̩ˈklɑːs', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:11'),
(16712, 'might', 'might as well do sth', '[{"example": "Since it''s raining, we might as well watch a movie.", "meaning": "不妨做某事；倒不如做某事", "part_of_speech": "phrase", "example_chinese": "既然下雨了，我们不妨看场电影。"}]', '/maɪt æz wel/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:10'),
(16713, 'migration', 'migration', '[{"example": "The birds'' migration south happens every winter.", "meaning": "迁徙；迁移", "part_of_speech": "noun", "example_chinese": "鸟类每年冬天都会向南迁徙。"}]', 'maɪˈgreɪ.ʃən', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:05'),
(16715, 'mile', 'miles', '[{"example": "My school is two miles away.", "meaning": "英里", "part_of_speech": "noun", "example_chinese": "我的学校在两英里外。"}]', '/maɪlz/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:09'),
(16716, 'miner', 'miner', '[{"example": "The miner found gold in the deep cave.", "meaning": "矿工", "part_of_speech": "noun", "example_chinese": "矿工在深洞里发现了黄金。"}]', 'ˈmaɪ.nər', 'C1', 'medium', 'work', '2025-10-20 08:00:00', '2025-10-21 16:18:14'),
(16717, 'mingle', 'mingle', '[{"example": "At the party, guests mingled and shared stories.", "meaning": "混合；交往", "part_of_speech": "verb", "example_chinese": "派对上，客人们互相交流并分享故事。"}]', 'ˈmɪŋ.gl ̩', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:16'),
(16718, 'minimal', 'minimal', '[{"example": "The design uses minimal colors.", "meaning": "最小的；极少的", "part_of_speech": "adjective", "example_chinese": "这个设计使用了极少的颜色。"}]', 'ˈmɪn.ɪ.məl', 'C1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 16:18:19'),
(16719, 'minimize', 'minimize', '[{"example": "We need to minimize the risks before starting the project.", "meaning": "最小化；使减至最低限度", "part_of_speech": "verb", "example_chinese": "在开始项目前，我们需要将风险降到最低。"}]', 'ˈmɪn.ɪ.maɪz', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:21'),
(16720, 'mining', 'mining', '[{"example": "The town grew rich from gold mining.", "meaning": "采矿，矿业", "part_of_speech": "noun", "example_chinese": "这个小镇因金矿开采而富裕起来。"}]', 'ˈmaɪ.nɪŋ', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:21'),
(16721, 'ministry', 'ministry', '[{"example": "My father works at the Ministry of Education.", "meaning": "政府部门", "part_of_speech": "noun", "example_chinese": "我父亲在教育部工作。"}]', 'ˈmɪn.ɪ.stri', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:15'),
(16723, 'misbehave', 'misbehave', '[{"example": "The children misbehave when they are tired.", "meaning": "行为不端", "part_of_speech": "verb", "example_chinese": "孩子们累了就会行为不端。"}]', 'ˌmɪs.bɪˈheɪv', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:28'),
(16724, 'misfortune', 'misfortune', '[{"example": "The broken vase was a small misfortune.", "meaning": "不幸；厄运", "part_of_speech": "noun", "example_chinese": "打碎的花瓶只是个小不幸。"}]', 'mɪsˈfɔː.tʃuːn', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:30'),
(16725, 'misinform', 'misinform', '[{"example": "The tabloid misinformed the public about the celebrity''s health.", "meaning": "误传；提供错误信息", "part_of_speech": "verb", "example_chinese": "这家小报对那位名人的健康状况进行了不实报道。"}]', 'ˌmɪs.ɪnˈfɔːm', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:26'),
(16726, 'mislead', 'mislead', '[{"example": "The fake news misled many people.", "meaning": "误导；欺骗", "part_of_speech": "verb", "example_chinese": "这条假新闻误导了很多人。"}]', 'mɪsˈliːd', 'C1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 16:18:23'),
(16727, 'mistaken', 'mistaken', '[{"example": "You are mistaken about the meeting time.", "meaning": "错误的，弄错的", "part_of_speech": "adjective", "example_chinese": "你搞错了会议时间。"}]', 'mɪˈsteɪ.kən', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:26'),
(16728, 'misuse', 'misuse', '[{"example": "The misuse of power can lead to serious consequences.", "meaning": "误用，滥用", "part_of_speech": "noun", "example_chinese": "滥用权力可能导致严重后果。"}]', 'ˌmɪsˈjuːz', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:31'),
(16730, 'mode', 'mode', '[{"example": "My phone is in silent mode during meetings.", "meaning": "模式，方式", "part_of_speech": "noun", "example_chinese": "开会时我的手机处于静音模式。"}, {"example": "Minimalism is the current mode in interior design.", "meaning": "风格，时尚", "part_of_speech": "noun", "example_chinese": "极简主义是当前室内设计的流行风格。"}]', 'məʊd', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:37'),
(16731, 'moderate', 'moderate', '[{"example": "The weather today is moderate, perfect for a picnic.", "meaning": "适度的；中等的", "part_of_speech": "adjective", "example_chinese": "今天天气温和，非常适合野餐。"}, {"example": "She moderates the discussion to keep it friendly.", "meaning": "使缓和；主持", "part_of_speech": "verb", "example_chinese": "她主持讨论以保持友好氛围。"}, {"example": "He is a moderate in political debates.", "meaning": "温和派；持中立观点者", "part_of_speech": "noun", "example_chinese": "他在政治辩论中是个温和派。"}]', 'ˈmɒd.ər.ət', 'C1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 16:18:38'),
(16733, 'modestly', 'modestly', '[{"example": "She smiled modestly when they praised her painting.", "meaning": "谦虚地；适度地", "part_of_speech": "adverb", "example_chinese": "他们称赞她的画时，她谦虚地笑了笑。"}]', 'ˈmɒd.ɪst.li', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:37'),
(16734, 'modification', 'modification', '[{"example": "The car needs some modifications to go faster.", "meaning": "修改，改变", "part_of_speech": "noun", "example_chinese": "这辆车需要一些改装才能跑得更快。"}]', 'ˌmɒd.ɪ.fɪˈkeɪ.ʃən', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:42'),
(16735, 'modify', 'modify', '[{"example": "I need to modify my recipe to make it healthier.", "meaning": "修改；调整", "part_of_speech": "verb", "example_chinese": "我需要修改我的食谱让它更健康。"}]', 'ˈmɒd.ɪ.faɪ', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:43');
