(16737, 'monotonous', 'monotonous', '[{"example": "The monotonous sound of the rain made him sleepy.", "meaning": "单调的，乏味的", "part_of_speech": "adjective", "example_chinese": "单调的雨声让他昏昏欲睡。"}]', 'məˈnɒt.ən.əs', 'C1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 16:18:47'),
(16739, 'motivate', 'motivate', '[{"example": "The coach''s speech motivated the team to win.", "meaning": "激励；激发", "part_of_speech": "verb", "example_chinese": "教练的演讲激励了队伍去赢得比赛。"}]', 'ˈməʊ.tɪ.veɪt', 'C1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 16:18:43'),
(16742, 'mouth', 'mouth of a river', '[{"example": "The ship sailed into the mouth of the river.", "meaning": "河口", "part_of_speech": "noun", "example_chinese": "船只驶入了河口。"}]', '/maʊθ əv ə ˈrɪvər/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:48'),
(16747, 'move', 'move on', '[{"example": "After the breakup, she decided to move on and focus on her career.", "meaning": "继续前进/放下过去", "part_of_speech": "verb", "example_chinese": "分手后，她决定放下过去，专注于事业。"}]', '/muːv ɒn/', 'C1', 'medium', 'people: actions, travel', '2025-10-20 08:00:00', '2025-10-21 16:18:52'),
(16751, 'multiple', 'multiple', '[{"example": "She has multiple hobbies like painting and swimming.", "meaning": "多个的；多样的", "part_of_speech": "adjective", "example_chinese": "她有多样的爱好，比如绘画和游泳。"}, {"example": "12 is a multiple of 3 and 4.", "meaning": "倍数", "part_of_speech": "noun", "example_chinese": "12是3和4的倍数。"}]', 'ˈmʌl.tɪ.pl ̩', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:55'),
(16752, 'mundane', 'mundane', '[{"example": "He grew tired of his mundane routine.", "meaning": "平凡的，普通的", "part_of_speech": "adjective", "example_chinese": "他开始厌倦自己平凡的日常。"}]', 'mʌnˈdeɪn', 'C1', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 16:18:53'),
(16753, 'municipal', 'municipal', '[{"example": "The municipal library has free Wi-Fi.", "meaning": "市政的；地方自治的", "part_of_speech": "adjective", "example_chinese": "市立图书馆提供免费Wi-Fi。"}]', 'mjuːˈnɪs.ɪ.pəl', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:18:57'),
(16755, 'mustard', 'mustard', '[{"example": "I put mustard on my hot dog.", "meaning": "芥末；芥菜", "part_of_speech": "noun", "example_chinese": "我在热狗上加了芥末。"}]', 'ˈmʌs.təd', 'C1', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 16:18:48'),
(16756, 'mutual', 'mutual', '[{"example": "Our mutual respect helps us work well together.", "meaning": "相互的", "part_of_speech": "adjective", "example_chinese": "我们相互的尊重帮助我们很好地合作。"}]', 'ˈmjuː.tʃu.əl', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:00'),
(16758, 'mysteriously', 'mysteriously', '[{"example": "The cat disappeared mysteriously.", "meaning": "神秘地", "part_of_speech": "adverb", "example_chinese": "那只猫神秘地消失了。"}]', 'mɪˈstɪə.ri.əs.li', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:02'),
(16760, 'naive', 'naive', '[{"example": "She was naive to believe his promises.", "meaning": "天真的，幼稚的", "part_of_speech": "adjective", "example_chinese": "她太天真了，竟然相信他的承诺。"}]', 'naɪˈiːv', 'C1', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:18:58'),
(16762, 'namely', 'namely', '[{"example": "We have two pets, namely a cat and a dog.", "meaning": "即，也就是", "part_of_speech": "adverb", "example_chinese": "我们有两只宠物，即一只猫和一只狗。"}]', 'ˈneɪm.li', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:05'),
(16763, 'nap', 'nap', '[{"example": "The cat took a short nap on the sofa.", "meaning": "小睡", "part_of_speech": "noun", "example_chinese": "猫在沙发上小睡了一会儿。"}, {"example": "The velvet has a soft nap.", "meaning": "绒毛", "part_of_speech": "noun", "example_chinese": "这块天鹅绒有柔软的绒毛。"}]', 'næp', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:05'),
(16765, 'narrow-minded', 'narrow-minded', '[{"example": "His narrow-minded views surprised everyone.", "meaning": "心胸狭窄的；思想狭隘的", "part_of_speech": "adjective", "example_chinese": "他狭隘的观点让所有人惊讶。"}]', 'ˌnær.əʊˈmaɪn.dɪd', 'C1', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:19:07'),
(16769, 'neatly', 'neatly', '[{"example": "She folded the clothes neatly.", "meaning": "整洁地；利落地", "part_of_speech": "adverb", "example_chinese": "她把衣服叠得整整齐齐。"}]', 'ˈniːt.li', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:10'),
(16770, 'necessity', 'necessity', '[{"example": "Water is a necessity for all living things.", "meaning": "必需品；必要性", "part_of_speech": "noun", "example_chinese": "水是所有生物的必需品。"}]', 'nəˈses.ə.ti', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:09'),
(16772, 'needless', 'needless to say', '[{"example": "Needless to say, the cat won the race easily.", "meaning": "不用说", "part_of_speech": "adverb", "example_chinese": "不用说，那只猫轻松赢得了比赛。"}]', '/ˈniːdləs tə seɪ/', 'C1', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 16:19:12'),
(16774, 'neglect', 'neglect', '[{"example": "Don''t neglect your homework!", "meaning": "忽视；疏忽", "part_of_speech": "verb", "example_chinese": "不要忽视你的作业！"}, {"example": "The old house fell into neglect.", "meaning": "疏忽；忽视", "part_of_speech": "noun", "example_chinese": "这栋老房子因无人照料而破败。"}]', 'nɪˈglekt', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:16'),
(16776, 'negotiate', 'negotiate', '[{"example": "Let''s negotiate a better price for this toy.", "meaning": "谈判；协商", "part_of_speech": "verb", "example_chinese": "我们为这个玩具谈个更好的价格吧。"}, {"example": "The cat negotiated the fence gracefully.", "meaning": "顺利通过", "part_of_speech": "verb", "example_chinese": "小猫优雅地翻过了栅栏。"}]', 'nɪˈgəʊ.ʃi.eɪt', 'C1', 'medium', 'communication, politics', '2025-10-20 08:00:00', '2025-10-21 16:19:20'),
(16777, 'negotiation', 'negotiation', '[{"example": "The business negotiation ended with a happy handshake.", "meaning": "谈判，协商", "part_of_speech": "noun", "example_chinese": "商业谈判以愉快的握手结束。"}]', 'nɪˌgəʊ.ʃiˈeɪ.ʃən', 'C1', 'medium', 'communication, politics', '2025-10-20 08:00:00', '2025-10-21 16:19:19'),
