(16783, 'networking', 'networking', '[{"example": "Networking helps people find new jobs.", "meaning": "网络构建", "part_of_speech": "noun", "example_chinese": "社交网络能帮助人们找到新工作。"}]', 'ˈnet.wɜː.kɪŋ', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:24'),
(16784, 'neutral', 'neutral', '[{"example": "Switzerland remained neutral during the war.", "meaning": "中立的；中性的", "part_of_speech": "adjective", "example_chinese": "瑞士在战争中保持中立。"}, {"example": "Put the car in neutral before starting the engine.", "meaning": "中立者；空挡", "part_of_speech": "noun", "example_chinese": "启动发动机前将档位挂在空挡。"}]', 'ˈnjuː.trəl', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:27'),
(16786, 'never-ending', 'never-ending', '[{"example": "Learning is a never-ending journey.", "meaning": "永无止境的；不断的", "part_of_speech": "adjective", "example_chinese": "学习是一段永无止境的旅程。"}]', 'ˌnev.ərˈend.ɪŋ', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:14'),
(16787, 'blood', 'new blood', '[{"example": "The company needs new blood to bring fresh ideas.", "meaning": "新鲜血液；新成员", "part_of_speech": "noun", "example_chinese": "公司需要新鲜血液来带来新想法。"}]', '/njuː blʌd/', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:31'),
(16789, 'newsletter', 'newsletter', '[{"example": "I subscribe to a weekly newsletter about gardening tips.", "meaning": "通讯；简报", "part_of_speech": "noun", "example_chinese": "我订阅了一份关于园艺技巧的每周通讯。"}]', 'ˈnjuːzˌlet.ər', 'C1', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:19:30'),
