(19608, 'passport', 'a passport to sth', '[{"example": "A good education is a passport to success.", "meaning": "获得…的途径/保障", "part_of_speech": "noun", "example_chinese": "良好的教育是通往成功的保障。"}]', '/ə ˈpɑːspɔːt tə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:43'),
(19609, 'plethora', 'a plethora of sth', '[{"example": "The garden has a plethora of colorful flowers.", "meaning": "大量，过多", "part_of_speech": "noun", "example_chinese": "花园里有大量色彩缤纷的花朵。"}]', '/plɛˈθɔːrə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:40'),
(19610, 'apologetic', 'apologetic', '[{"example": "He gave an apologetic smile when he arrived late.", "meaning": "道歉的，愧疚的", "part_of_speech": "adjective", "example_chinese": "他迟到时露出了歉意的微笑。"}]', 'əˌpɒl.əˈdʒe.tɪk', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:42:48'),
(19615, 'apply', 'apply yourself', '[{"example": "If you apply yourself, you can finish the puzzle quickly.", "meaning": "专心致志；努力做", "part_of_speech": "verb phrase", "example_chinese": "如果你专心致志，就能很快完成这个拼图。"}]', '/əˈplaɪ jɔːˈself/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:43'),
(19618, 'profound', 'a profound effect/impact/influence, etc.', '[{"example": "The teacher''s words had a profound effect on my life.", "meaning": "深远影响", "part_of_speech": "noun", "example_chinese": "老师的话对我的人生产生了深远影响。"}]', '/prəˈfaʊnd ɪˈfɛkt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:48'),
(19619, 'public', 'a public announcement/appearance/statement, etc.', '[{"example": "The mayor made a public announcement about the new park.", "meaning": "公开声明", "part_of_speech": "noun", "example_chinese": "市长就新公园发表了公开声明。"}, {"example": "The celebrity''s first public appearance drew a huge crowd.", "meaning": "公开露面", "part_of_speech": "noun", "example_chinese": "这位名人的首次公开露面吸引了大量人群。"}, {"example": "The company issued a public statement to clarify the situation.", "meaning": "公开声明", "part_of_speech": "noun", "example_chinese": "公司发表公开声明以澄清情况。"}]', '/ˈpʌblɪk əˈnaʊnsmənt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:52'),
(19620, 'ray', 'a ray of comfort/hope, etc.', '[{"example": "The kind words from her friend were a ray of comfort during her difficult time.", "meaning": "一丝安慰/希望等", "part_of_speech": "noun", "example_chinese": "朋友温暖的话语在她困难时期带来了一丝安慰。"}]', '/ə ˈreɪ əv ˈkʌmfət/', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:42:55'),
(19621, 'arbitrary', 'arbitrary', '[{"example": "The teacher made an arbitrary decision to cancel the test.", "meaning": "任意的，武断的", "part_of_speech": "adjective", "example_chinese": "老师武断地决定取消考试。"}]', 'ˈɑː.bɪt.rər.i', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:42:54'),
(19622, 'arch', 'arch', '[{"example": "The rainbow formed a perfect arch in the sky.", "meaning": "拱门；拱形结构", "part_of_speech": "noun", "example_chinese": "彩虹在天空中形成了一道完美的拱形。"}, {"example": "The cat arched its back when it saw the dog.", "meaning": "拱起；成弓形", "part_of_speech": "verb", "example_chinese": "猫看到狗时弓起了背。"}, {"example": "She gave me an arch smile before telling the joke.", "meaning": "调皮的；主要的", "part_of_speech": "adjective", "example_chinese": "在讲笑话前，她给了我一个调皮的笑容。"}]', 'ɑːtʃ', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:04'),
