(19625, 'riot', 'a riot of sth', '[{"example": "The garden was a riot of colors in spring.", "meaning": "丰富多彩的某物；五光十色的景象", "part_of_speech": "noun", "example_chinese": "春天花园里五彩斑斓。"}]', '/ə ˈraɪət əv/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:01'),
(19627, 'armed', 'armed with sth', '[{"example": "The detective was armed with new evidence.", "meaning": "装备有；携带着；具备（知识、信息等）", "part_of_speech": "phrase", "example_chinese": "侦探掌握了新证据。"}]', '/ɑːrmd wɪð/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:07'),
(19628, 'arm', 'arm in arm', '[{"example": "The friends walked arm in arm through the park.", "meaning": "臂挽臂地", "part_of_speech": "adverb", "example_chinese": "朋友们臂挽臂地穿过公园散步。"}]', '/ɑːm ɪn ɑːm/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:09'),
(19629, 'army', 'army', '[{"example": "My brother serves in the army.", "meaning": "军队", "part_of_speech": "noun", "example_chinese": "我哥哥在军队服役。"}]', 'ˈɑː.mi', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:06'),
(19630, 'head', 'a roof over your head', '[{"example": "After losing his job, he just wanted a roof over his head.", "meaning": "栖身之所，安身之处", "part_of_speech": "noun", "example_chinese": "失业后，他只想要个安身之处。"}]', '/ə ruːf ˈəʊvə jɔː hed/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:13'),
(19632, 'ride', 'a rough/bumpy ride', '[{"example": "The old bus gave us a bumpy ride through the mountains.", "meaning": "颠簸的旅程；艰难的过程", "part_of_speech": "noun", "example_chinese": "那辆旧巴士载着我们在山中颠簸前行。"}]', '/ə ˌrʌf/ˈbʌmpi raɪd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:12'),
(19634, 'corner', 'around/round the corner', '[{"example": "The weekend is just around the corner!", "meaning": "即将发生；在附近", "part_of_speech": "idiom", "example_chinese": "周末马上就要到了！"}, {"example": "There''s a cute café right round the corner.", "meaning": "在拐角处", "part_of_speech": "idiom", "example_chinese": "拐角处就有一家可爱的咖啡馆。"}]', '/əˈraʊnd ðə ˈkɔːnə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:35'),
