(19637, 'arrive', 'arrive at an answer/conclusion/decision, etc.', '[{"example": "After hours of discussion, we finally arrived at a decision.", "meaning": "得出结论/做出决定", "part_of_speech": "verb phrase", "example_chinese": "经过数小时讨论，我们最终做出了决定。"}, {"example": "The students worked together to arrive at the correct answer.", "meaning": "得出答案", "part_of_speech": "verb phrase", "example_chinese": "学生们一起努力得出了正确答案。"}, {"example": "The research team arrived at an interesting conclusion.", "meaning": "达成结论", "part_of_speech": "verb phrase", "example_chinese": "研究团队得出了一个有趣的结论。"}]', '/əˈraɪv æt ə dɪˈsɪʒən/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:26'),
(19639, 'artificial intelligence', 'artificial intelligence', '[{"example": "Artificial intelligence helps robots recognize faces.", "meaning": "人工智能", "part_of_speech": "noun", "example_chinese": "人工智能帮助机器人识别人脸。"}]', 'ˌɑː.tɪˌfɪʃ.əl.ɪnˈtel.ɪ.dʒənts', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:18'),
(19640, 'inclined', 'artistically/technically, etc. inclined', '[{"example": "She''s artistically inclined and paints beautiful landscapes.", "meaning": "有艺术天赋的", "part_of_speech": "adjective", "example_chinese": "她很有艺术天赋，画出了美丽的风景。"}, {"example": "He''s technically inclined and fixes all our computer problems.", "meaning": "有技术天赋的", "part_of_speech": "adjective", "example_chinese": "他很有技术天赋，解决了我们所有的电脑问题。"}]', '/ɑːˈtɪstɪkli ɪnˈklaɪnd/', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:43:27'),
(19641, 'run', 'a run of sth', '[{"example": "The team had a run of five wins in a row.", "meaning": "一连串（相似事件）", "part_of_speech": "noun", "example_chinese": "这支队伍取得了一波五连胜。"}]', '/ə rʌn əv/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:21'),
