(19645, 'sharp', 'a sharp contrast/difference, etc.', '[{"example": "There is a sharp contrast between summer and winter here.", "meaning": "鲜明对比", "part_of_speech": "noun", "example_chinese": "这里的夏天和冬天形成鲜明对比。"}, {"example": "The twins have a sharp difference in personality.", "meaning": "明显差异", "part_of_speech": "noun", "example_chinese": "这对双胞胎性格有明显差异。"}]', '/ʃɑːrp ˈkɒntrɑːst/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:36'),
(19646, 'pain', 'a sharp pain', '[{"example": "He felt a sharp pain in his chest when he ran too fast.", "meaning": "剧痛", "part_of_speech": "noun", "example_chinese": "他跑太快时感到胸口一阵剧痛。"}]', '/ʃɑːrp peɪn/', 'C2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 16:43:40'),
(19648, 'cry', 'a shoulder to cry on', '[{"example": "When I felt sad, my best friend became a shoulder to cry on.", "meaning": "可以倾诉痛苦的对象，情感依靠", "part_of_speech": "noun", "example_chinese": "当我感到难过时，我最好的朋友成了我可以倾诉痛苦的对象。"}]', '/ə ˈʃəʊldə tə kraɪ ɒn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:43'),
