(19653, 'face', 'a slap in the face', '[{"example": "His criticism was a real slap in the face.", "meaning": "公然侮辱；突如其来的打击", "part_of_speech": "noun", "example_chinese": "他的批评真是当头一棒。"}]', '/slæp ɪn ðə feɪs/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:48'),
(19655, 'degree', 'a/some degree of sth', '[{"example": "Learning a language requires a degree of patience.", "meaning": "一定程度的某事物", "part_of_speech": "noun", "example_chinese": "学习语言需要一定程度的耐心。"}]', '/ə dɪˈɡriː əv/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:37'),
(19656, 'as', 'as opposed to', '[{"example": "I prefer tea as opposed to coffee.", "meaning": "与...相对，而不是", "part_of_speech": "preposition", "example_chinese": "我喜欢茶而不是咖啡。"}]', '/æz əˈpəʊzd tuː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:51'),
(19658, 'point', 'a sore point', '[{"example": "His low grades are a sore point with his parents.", "meaning": "痛处；伤心事", "part_of_speech": "noun", "example_chinese": "他的低分是他父母的痛处。"}]', '/ə sɔː pɔɪnt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:54'),
