(19661, 'aspire', 'aspire to sth; aspire to do sth', '[{"example": "She aspires to become a scientist who changes the world.", "meaning": "渴望（成就某事）；立志（做某事）", "part_of_speech": "verb", "example_chinese": "她渴望成为改变世界的科学家。"}]', '/əˈspaɪə(r) tuː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:50'),
(19662, 'assault', 'assault', '[{"example": "The soldiers launched a sudden assault on the enemy castle.", "meaning": "攻击；袭击", "part_of_speech": "noun", "example_chinese": "士兵们对敌方城堡发动了突然袭击。"}, {"example": "The hero assaulted the dragon with his magical sword.", "meaning": "攻击；袭击", "part_of_speech": "verb", "example_chinese": "英雄用他的魔法剑攻击了巨龙。"}]', 'əˈsɔːlt', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:44:08'),
