(19666, 'assembly', 'assembly', '[{"example": "The school assembly will start at 9 AM.", "meaning": "集会；组装", "part_of_speech": "noun", "example_chinese": "学校集会将在上午9点开始。"}]', 'əˈsem.bli', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:43:56'),
(19668, 'assertive', 'assertive', '[{"example": "She gave an assertive answer in the meeting.", "meaning": "果断的；自信的", "part_of_speech": "adjective", "example_chinese": "她在会议上给出了一个果断的回答。"}]', 'əˈsɜː.tɪv', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 16:44:01'),
