(19672, 'associate', 'associate with sb', '[{"example": "I like to associate with positive people.", "meaning": "与某人交往/联系", "part_of_speech": "verb", "example_chinese": "我喜欢和积极的人交往。"}]', '/əˈsəʊʃieɪt wɪð/', 'C2', 'medium', 'relationships', '2025-10-20 08:00:00', '2025-10-21 16:44:12'),
(19674, 'assume', 'assume control/power/responsibility, etc.', '[{"example": "The new CEO will assume control of the company next week.", "meaning": "承担（控制权/权力/责任等）", "part_of_speech": "verb", "example_chinese": "新任CEO将于下周接管公司。"}, {"example": "She assumed responsibility for the project with enthusiasm.", "meaning": "担任（职务）", "part_of_speech": "verb", "example_chinese": "她热情地承担起这个项目的责任。"}, {"example": "The young prince assumed power after his father''s death.", "meaning": "掌握（权力）", "part_of_speech": "verb", "example_chinese": "年轻的王子在父亲去世后继承了王位。"}]', '/əˈsjuːm kənˈtrəʊl/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:44:22'),
