(19839, 'foreign', 'be foreign to sb', '[{"example": "The concept of working from home is completely foreign to my grandfather.", "meaning": "对某人来说陌生/不熟悉", "part_of_speech": "adjective", "example_chinese": "在家工作的概念对我祖父来说完全陌生。"}]', '/ˈfɒr.ən/ /tuː/ ˈsʌm.bɒdi', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:47:34'),
