(19841, 'catch', 'be/get caught', '[{"example": "The thief got caught stealing cookies.", "meaning": "被抓住/被发现", "part_of_speech": "verb phrase", "example_chinese": "小偷在偷饼干时被抓住了。"}, {"example": "We got caught in the rain without umbrellas.", "meaning": "被困住", "part_of_speech": "verb phrase", "example_chinese": "我们没带伞被雨困住了。"}]', '/biː kɔːt/ /ɡet kɔːt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:47:44'),
(19842, 'catch', 'be/get caught up in sth', '[{"example": "She got caught up in the exciting movie and forgot the time.", "meaning": "被卷入；沉迷于", "part_of_speech": "phrasal verb", "example_chinese": "她沉迷于那部刺激的电影，忘记了时间。"}]', '/biː kɔːt ʌp ɪn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:47:41'),
(19843, 'out of', 'be/get out of touch', '[{"example": "After moving abroad, I got out of touch with my old friends.", "meaning": "失去联系；脱离现实", "part_of_speech": "phrase", "example_chinese": "移居国外后，我和老朋友们失去了联系。"}]', '/biː ɡet aʊt əv tʌtʃ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:47:47'),
