(19846, 'glue', 'be glued to sth', '[{"example": "The children were glued to the cartoon on TV.", "meaning": "全神贯注于某事物", "part_of_speech": "phrasal verb", "example_chinese": "孩子们全神贯注地看着电视上的卡通片。"}]', '/biː ɡluːd tə ˈsʌmθɪŋ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:47:50'),
