(19940, 'apart', 'be poles apart', '[{"example": "Their opinions on this matter are poles apart.", "meaning": "截然不同；天差地别", "part_of_speech": "idiom", "example_chinese": "他们在这个问题上的看法截然不同。"}]', '/pəʊlz əˈpɑːt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:51'),
(19942, 'post', 'be posted to France/London/Singapore, etc.', '[{"example": "My colleague will be posted to Singapore next month for a new project.", "meaning": "被派往法国/伦敦/新加坡等地", "part_of_speech": "verb phrase", "example_chinese": "我的同事下个月将被派往新加坡负责一个新项目。"}]', '/biː ˈpəʊstɪd tə frɑːns/ˈlʌndən/ˌsɪŋəˈpɔː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:45'),
(19943, 'prone', 'be prone to sth/doing sth', '[{"example": "Children are prone to catching colds in winter.", "meaning": "易于…的；有…倾向的", "part_of_speech": "adjective", "example_chinese": "孩子们冬天容易感冒。"}, {"example": "He''s prone to forget meetings without reminders.", "meaning": "很可能做…的", "part_of_speech": "adjective", "example_chinese": "没有提醒的话他很容易忘记开会。"}]', '/prəʊn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:50'),
(19944, 'reliant', 'be reliant on sb/sth', '[{"example": "The little bird is reliant on its mother for food.", "meaning": "依赖某人/某事物", "part_of_speech": "adjective", "example_chinese": "小鸟依赖妈妈获取食物。"}]', '/rɪˈlaɪənt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:45'),
(19945, 'revolt', 'be revolted by sth', '[{"example": "I am revolted by the smell of rotten eggs.", "meaning": "对...感到厌恶", "part_of_speech": "verb", "example_chinese": "我讨厌臭鸡蛋的味道。"}]', '/rɪˈvɒltɪd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:56'),
(19946, 'counter', 'be/run counter to sth', '[{"example": "His actions run counter to his words.", "meaning": "与...相反/相悖", "part_of_speech": "phrase", "example_chinese": "他的行为与他的言论相悖。"}]', '/biː ˈraʊn ˈkaʊntə tuː ˈsʌmθɪŋ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:51'),
(19947, 'run', 'be running at sth', '[{"example": "Inflation is running at 5% this year.", "meaning": "达到某种水平或数量", "part_of_speech": "phrasal verb", "example_chinese": "今年通货膨胀率达到了5%。"}]', '/biː ˈrʌnɪŋ æt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:56'),
(19948, 'beside', 'beside the point', '[{"example": "Your excuse is beside the point.", "meaning": "离题/不相关", "part_of_speech": "idiom", "example_chinese": "你的借口不相关。"}]', '/bɪˈsaɪd ðə pɔɪnt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:49:56'),
(19950, 'slow', 'be slow to do sth; be slow in doing sth', '[{"example": "The old computer is slow to start up every morning.", "meaning": "做某事迟缓/不情愿", "part_of_speech": "phrase", "example_chinese": "这台旧电脑每天早上启动都很慢。"}]', '/bi sləʊ tə duː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:01'),
(19951, 'snow', 'be snowed in', '[{"example": "We were snowed in for three days and couldn''t leave the house.", "meaning": "被大雪困住", "part_of_speech": "verb phrase", "example_chinese": "我们被大雪困了三天，无法离开房子。"}]', '/bi ˈsnəʊd ɪn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:03'),
(19952, 'snow', 'be snowed under', '[{"example": "I''m completely snowed under with work this week.", "meaning": "忙得不可开交", "part_of_speech": "phrasal verb", "example_chinese": "这周我完全被工作淹没了。"}]', '/bi ˈsnəʊd ˈʌndə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:07'),
(19953, 'something', 'be something', '[{"example": "She''s really going to be something one day.", "meaning": "了不起的人/物；重要人物", "part_of_speech": "idiom", "example_chinese": "她总有一天会成为了不起的人物。"}]', '/bi ˈsʌmθɪŋ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:07'),
(19954, 'go', 'be still going strong', '[{"example": "My grandfather is 90 years old and still going strong!", "meaning": "依然强劲；保持良好状态", "part_of_speech": "phrase", "example_chinese": "我爷爷90岁了，身体依然很硬朗！"}]', '/biː stɪl ˈɡəʊɪŋ strɒŋ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:02'),
(19956, 'street', 'be streets ahead (of sb/sth)', '[{"example": "Her coding skills are streets ahead of other interns.", "meaning": "遥遥领先；远胜于", "part_of_speech": "idiom", "example_chinese": "她的编程能力远超其他实习生。"}]', '/striːts əˈhɛd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:13'),
(19958, 'attention', 'be the centre of attention', '[{"example": "The little girl in the pink dress loves to be the centre of attention.", "meaning": "成为关注焦点", "part_of_speech": "phrase", "example_chinese": "穿粉色裙子的小女孩喜欢成为众人关注的焦点。"}]', '/bi ðə ˈsɛntər ɒv əˈtɛnʃən/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:08'),
(19960, 'envy', 'be the envy of sb', '[{"example": "Her new sports car is the envy of all her friends.", "meaning": "令某人羡慕的事物/人", "part_of_speech": "phrase", "example_chinese": "她的新跑车让所有朋友都羡慕不已。"}]', '/bi ðə ˈɛnvi ɒv ˈsʌmbɒdi/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:13'),
(19961, 'iceberg', 'be the tip of the iceberg', '[{"example": "The few mistakes we found are just the tip of the iceberg.", "meaning": "冰山一角", "part_of_speech": "idiom", "example_chinese": "我们发现的几个错误只是冰山一角。"}]', '/ðə tɪp əv ði ˈaɪsbɜːɡ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:14'),
(19963, 'top', 'be topped with sth', '[{"example": "The cake is topped with strawberries.", "meaning": "顶部覆盖着某物", "part_of_speech": "verb phrase", "example_chinese": "蛋糕顶部覆盖着草莓。"}]', '/tɒpt wɪð/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:18'),
(19964, 'tear', '(be) torn between sth and sth', '[{"example": "She was torn between studying art and becoming a doctor.", "meaning": "在...和...之间难以抉择", "part_of_speech": "adjective phrase", "example_chinese": "她在学习艺术和成为医生之间难以抉择。"}]', '/tɔːn bɪˈtwiːn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:19'),
(19965, 'under', 'be under way', '[{"example": "The school project is under way and we are excited!", "meaning": "正在进行中", "part_of_speech": "verb_phrase", "example_chinese": "学校项目正在进行中，我们很兴奋！"}]', '/bi ˈʌndər weɪ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:29'),
(19967, 'waste', 'be wasted on sb', '[{"example": "Good advice is wasted on him.", "meaning": "被浪费在某人身上（指某物对某人未产生应有价值）", "part_of_speech": "phrase", "example_chinese": "好建议用在他身上纯属浪费。"}]', '/biː ˈweɪstɪd ɒn ˈsʌmbədi/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:20'),
(19968, 'awake', 'be wide awake', '[{"example": "After drinking coffee, I''m wide awake now!", "meaning": "完全清醒的", "part_of_speech": "adjective", "example_chinese": "喝完咖啡后，我现在完全清醒了！"}]', '/waɪd əˈweɪk/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:24'),
(19970, 'foundation', 'be without foundation; have no foundation', '[{"example": "His crazy theory is without foundation.", "meaning": "毫无根据", "part_of_speech": "verb", "example_chinese": "他的疯狂理论毫无根据。"}, {"example": "Their relationship has no foundation.", "meaning": "没有基础", "part_of_speech": "verb", "example_chinese": "他们的关系没有基础。"}]', '/wɪˈðaʊt faʊnˈdeɪʃən/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:27'),
(19971, 'while', 'be worth your while', '[{"example": "Reading this book will be worth your while.", "meaning": "值得花费时间/精力", "part_of_speech": "idiom", "example_chinese": "读这本书会值得你花时间的。"}]', '/biː wɜːθ jɔː waɪl/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:26'),
(19974, 'belief', 'beyond belief', '[{"example": "The magician''s trick was beyond belief!", "meaning": "难以置信", "part_of_speech": "phrase", "example_chinese": "魔术师的把戏令人难以置信！"}]', '/bɪˈjɒnd bɪˈliːf/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:32'),
(19976, 'beyond', 'beyond dispute', '[{"example": "His talent is beyond dispute.", "meaning": "无可争议", "part_of_speech": "phrase", "example_chinese": "他的才华无可争议。"}]', '/bɪˈjɒnd dɪˈspjuːt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:34'),
(19978, 'beyond', 'beyond (sb''s) reach', '[{"example": "The cookie jar is beyond the child''s reach on the top shelf.", "meaning": "无法触及/超出能力范围", "part_of_speech": "phrase", "example_chinese": "饼干罐放在顶层架子上，孩子够不着。"}]', '/bɪˈjɒnd (ˌsʌmbɒdiːz) riːtʃ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:38'),
(19980, 'doubt', 'beyond/without a/the shadow of a doubt', '[{"example": "The evidence proved his guilt beyond a shadow of a doubt.", "meaning": "毫无疑问，确凿无疑", "part_of_speech": "phrase", "example_chinese": "证据确凿无疑地证明了他的罪行。"}, {"example": "She is without the shadow of a doubt the best candidate for the job.", "meaning": "毫无疑义，千真万确", "part_of_speech": "phrase", "example_chinese": "她千真万确是这份工作的最佳人选。"}]', '/bɪˈjɒnd/ /ə/ /ˈʃædəʊ/ /əv/ /ə/ /daʊt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:43'),
(19982, 'beyond', 'beyond your wildest dreams', '[{"example": "The trip was amazing beyond my wildest dreams!", "meaning": "超乎想象", "part_of_speech": "phrase", "example_chinese": "这次旅行精彩得超乎我的想象！"}]', '/bɪˈjɒnd jɔːr ˈwaɪldɪst driːmz/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:40'),
(19985, 'bias', 'bias', '[{"example": "The judge had no bias in the competition.", "meaning": "偏见", "part_of_speech": "noun", "example_chinese": "裁判在比赛中没有偏见。"}]', 'ˈbaɪ.əs', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:32'),
(19989, 'bind', 'bind', '[{"example": "The book is bound in leather.", "meaning": "捆绑；约束", "part_of_speech": "verb", "example_chinese": "这本书是用皮革装订的。"}, {"example": "He found himself in a bind.", "meaning": "困境；束缚", "part_of_speech": "noun", "example_chinese": "他发现自己陷入了困境。"}]', 'baɪnd', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:47'),
(19991, 'bit', 'bits and pieces', '[{"example": "I keep my bits and pieces in this small box.", "meaning": "零碎东西；零星物品", "part_of_speech": "noun", "example_chinese": "我把零碎东西都放在这个小盒子里。"}]', '/ˌbɪts ən ˈpiːsɪz/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:44'),
(19993, 'blackmail', 'blackmail', '[{"example": "He used the photos for blackmail.", "meaning": "敲诈；勒索", "part_of_speech": "noun", "example_chinese": "他用这些照片进行敲诈。"}]', 'ˈblæk.meɪl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:48'),
(19995, 'bland', 'bland', '[{"example": "The soup was too bland for my taste.", "meaning": "清淡的；乏味的", "part_of_speech": "adjective", "example_chinese": "这汤对我来说太清淡了。"}]', 'blænd', 'C2', 'medium', 'food and drink', '2025-10-20 08:00:00', '2025-10-21 16:50:48'),
(19999, 'bleak', 'bleak', '[{"example": "The bleak winter sky made everyone feel gloomy.", "meaning": "阴冷的；荒凉的；无望的", "part_of_speech": "adjective", "example_chinese": "阴冷的冬日天空让所有人都感到压抑。"}]', 'bliːk', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:52'),
(20001, 'blend', 'blend', '[{"example": "Blend the ingredients until smooth.", "meaning": "混合", "part_of_speech": "verb", "example_chinese": "将原料混合至顺滑。"}, {"example": "This coffee is a blend of three beans.", "meaning": "混合物", "part_of_speech": "noun", "example_chinese": "这种咖啡是三种豆子的混合物。"}]', 'blend', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:04'),
(20003, 'blister', 'blister', '[{"example": "I got a blister on my heel from the new shoes.", "meaning": "水疱", "part_of_speech": "noun", "example_chinese": "新鞋子让我的脚后跟起了个水疱。"}, {"example": "There was a blister in the old painting.", "meaning": "气泡", "part_of_speech": "noun", "example_chinese": "这幅旧画上有个气泡。"}]', 'ˈblɪs.tər', 'C2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 16:50:56'),
(20011, 'blow', 'blow it/your chance(s)', '[{"example": "He blew his chance to win by arriving late.", "meaning": "搞砸机会", "part_of_speech": "verb_phrase", "example_chinese": "他因为迟到搞砸了获胜的机会。"}]', '/bləʊ ɪt/ /jɔː tʃɑːnsɪz/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:50:55'),
(20013, 'blow', 'blow your mind', '[{"example": "The magic trick will blow your mind!", "meaning": "令人震惊/大开眼界", "part_of_speech": "verb phrase", "example_chinese": "这个魔术会让你大开眼界！"}, {"example": "The scientific discovery blew my mind.", "meaning": "颠覆认知", "part_of_speech": "verb phrase", "example_chinese": "这个科学发现颠覆了我的认知。"}]', '/bləʊ jɔː maɪnd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:00'),
(20016, 'blunt', 'blunt', '[{"example": "He cut the rope with a blunt knife.", "meaning": "钝的；直率的", "part_of_speech": "adjective", "example_chinese": "他用一把钝刀割断了绳子。"}, {"example": "Time blunts the sharpest memories.", "meaning": "使变钝；减弱", "part_of_speech": "verb", "example_chinese": "时间会磨灭最深刻的记忆。"}]', 'blʌnt', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:03'),
(20020, 'body', 'body and soul', '[{"example": "She put her body and soul into the performance.", "meaning": "全心全意；整个身心", "part_of_speech": "noun", "example_chinese": "她全身心投入到表演中。"}]', '/ˈbɒdi ənd səʊl/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:05'),
(20022, 'squad', 'bomb/drug/fraud, etc. squad', '[{"example": "The bomb squad safely removed the suspicious package.", "meaning": "特别行动队/专案组", "part_of_speech": "noun", "example_chinese": "炸弹处理小组安全移除了可疑包裹。"}]', '/bɒm skwɒd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:09'),
(20026, 'bound', 'bound up with sth', '[{"example": "Her happiness is bound up with her family''s success.", "meaning": "与...紧密相连", "part_of_speech": "adjective", "example_chinese": "她的幸福与家庭的成功紧密相连。"}]', '/baʊnd ʌp wɪð/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:11'),
(20034, 'break', 'break free', '[{"example": "The bird broke free from the cage and flew away.", "meaning": "挣脱；摆脱束缚", "part_of_speech": "verb phrase", "example_chinese": "小鸟挣脱笼子飞走了。"}]', '/breɪk friː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:08'),
(20038, 'break', 'break new ground', '[{"example": "The scientist broke new ground in cancer research.", "meaning": "开创新领域，突破创新", "part_of_speech": "verb_phrase", "example_chinese": "这位科学家在癌症研究领域取得了突破性进展。"}]', '/breɪk njuː ɡraʊnd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:14'),
(20041, 'break', 'break the news to sb', '[{"example": "I had to break the news to Tom that his pet hamster escaped.", "meaning": "告知消息（常指坏消息）", "part_of_speech": "verb phrase", "example_chinese": "我不得不告诉汤姆他的仓鼠逃走了"}]', '/breɪk ðə njuːz tuː ˈsʌmbədi/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:15'),
(20043, 'breed', 'breed contempt/ignorance, etc.', '[{"example": "Familiarity breeds contempt in many relationships.", "meaning": "滋生轻蔑/无知等", "part_of_speech": "noun", "example_chinese": "亲密关系中熟悉常滋生轻蔑。"}]', '/ˈbriːd kənˈtempt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:16'),
(20044, 'bribery', 'bribery', '[{"example": "The official was arrested for taking bribery.", "meaning": "贿赂", "part_of_speech": "noun", "example_chinese": "这名官员因受贿被捕。"}]', 'ˈbraɪ.bər.i', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:19'),
(20046, 'bring', 'bring a lump to your throat', '[{"example": "The movie''s ending was so touching it brought a lump to my throat.", "meaning": "令人哽咽/感动", "part_of_speech": "idiom", "example_chinese": "电影的结局太感人了，让我哽咽不已。"}]', '/brɪŋ ə lʌmp tə jɔːr θroʊt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:20');
INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(20049, 'best', 'bring out the best in sb', '[{"example": "The teacher''s encouragement brought out the best in the shy student.", "meaning": "激发某人的最佳品质/潜能", "part_of_speech": "phrasal verb", "example_chinese": "老师的鼓励激发了这位害羞学生的最佳潜能。"}]', '/brɪŋ aʊt ðə best ɪn ˈsʌmbɒdi/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:23'),
(20051, 'bring', 'bring sth to light', '[{"example": "The investigation brought new evidence to light.", "meaning": "揭露；使暴露", "part_of_speech": "phrasal verb", "example_chinese": "调查揭露了新的证据。"}]', '/brɪŋ ˈsʌmθɪŋ tə laɪt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:51:24'),
