(20554, 'doom', 'doom', '[{"example": "The prophecy spoke of doom for the kingdom.", "meaning": "厄运，劫数", "part_of_speech": "noun", "example_chinese": "预言讲述了王国的厄运。"}]', 'duːm', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 16:59:55'),
