(20556, 'doorway', 'doorway', '[{"example": "The cat slept in the sunny doorway.", "meaning": "门口，出入口", "part_of_speech": "noun", "example_chinese": "猫咪在阳光明媚的门口睡觉。"}]', 'ˈdɔː.weɪ', 'C2', 'medium', 'buildings', '2025-10-20 08:00:00', '2025-10-21 17:00:01'),
