(20559, 'do', 'do sb/sth justice; do justice to sb/sth', '[{"example": "This photo doesn''t do justice to her beauty.", "meaning": "公平对待；充分展现（价值/优点）", "part_of_speech": "phrase", "example_chinese": "这张照片没拍出她的美。"}, {"example": "The review did justice to the chef''s creative dishes.", "meaning": "公正评价", "part_of_speech": "phrase", "example_chinese": "这篇评论公正评价了厨师的创意菜肴。"}]', '/duː ˈdʒʌstɪs tuː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:09'),
(20561, 'as', 'do sth as you see/think fit', '[{"example": "You can arrange the party as you see fit.", "meaning": "做你认为合适的事", "part_of_speech": "verb phrase", "example_chinese": "你可以按自己觉得合适的方式安排派对。"}]', '/duː ˈsʌmθɪŋ æz ju siː fɪt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:02'),
