(20566, 'do', 'do the job', '[{"example": "This simple tool will do the job for our project.", "meaning": "完成工作；解决问题", "part_of_speech": "verb phrase", "example_chinese": "这个简单工具能完成我们项目的工作。"}]', '/duː ðə dʒɒb/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:12'),
