(20570, 'down', 'down and out', '[{"example": "After losing his job and home, he was completely down and out.", "meaning": "穷困潦倒的；落魄的", "part_of_speech": "adjective", "example_chinese": "失去工作和住所后，他彻底穷困潦倒了。"}]', '/ˌdaʊn ən ˈaʊt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:15'),
(20572, 'downhill', 'downhill', '[{"example": "The downhill ride was thrilling!", "meaning": "下坡的/地", "part_of_speech": "adjective/adverb", "example_chinese": "下坡骑行太刺激了！"}, {"example": "Skiers love the steep downhill.", "meaning": "下坡路段", "part_of_speech": "noun", "example_chinese": "滑雪者喜欢陡峭的下坡。"}]', 'ˌdaʊnˈhɪl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:20'),
(20573, 'down', 'down the drain', '[{"example": "All my hard work went down the drain when the project was canceled.", "meaning": "白费力气；付诸东流", "part_of_speech": "idiom", "example_chinese": "项目取消后，我所有的努力都白费了。"}]', '/daʊn ðə dreɪn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:23'),
