(20577, 'thing', 'do your own thing', '[{"example": "At the party, some danced while others just did their own thing.", "meaning": "做自己的事；我行我素", "part_of_speech": "phrase", "example_chinese": "派对上有人跳舞，其他人则自顾自做事。"}]', '/duː jɔːr əʊn θɪŋ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:27'),
(20579, 'drag', 'drag sb along/out/to, etc.', '[{"example": "I dragged my brother along to the concert.", "meaning": "硬拉某人一起去/外出/到某处", "part_of_speech": "phrasal verb", "example_chinese": "我硬拉着我弟弟一起去音乐会。"}, {"example": "She dragged me out to see the boring movie.", "meaning": "勉强带某人参加", "part_of_speech": "phrasal verb", "example_chinese": "她勉强带我出去看那部无聊的电影。"}]', '/dræɡ ˌsʌmbɒdi əˈlɒŋ/ /aʊt/ /tuː/', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:00:33'),
(20580, 'drain', 'drain', '[{"example": "The bathtub drain is clogged with hair.", "meaning": "排水管；消耗", "part_of_speech": "noun", "example_chinese": "浴缸排水管被头发堵住了。"}]', 'dreɪn', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:20'),
(20585, 'draw', 'draw a comparison/distinction', '[{"example": "The teacher drew a comparison between bees and ants to show how they work together.", "meaning": "作比较/区分", "part_of_speech": "verb phrase", "example_chinese": "老师比较蜜蜂和蚂蚁来说明它们如何协作。"}, {"example": "Can you draw a distinction between these two shades of blue?", "meaning": "指出区别", "part_of_speech": "verb phrase", "example_chinese": "你能区分这两种蓝色吗？"}]', '/drɔː ə ˌkɒmpəˈrɪsən/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:35'),
(20586, 'draw', 'draw sth/sb across/back/over, etc.', '[{"example": "She drew the curtain across the window.", "meaning": "将某物/某人拉过/拉回/拉上等", "part_of_speech": "verb", "example_chinese": "她把窗帘拉上。"}]', '/drɔː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:31'),
(20587, 'draw', 'draw the line (at sth)', '[{"example": "I love dogs, but I draw the line at snakes as pets.", "meaning": "划定界限；拒绝做某事", "part_of_speech": "verb phrase", "example_chinese": "我喜欢狗，但拒绝把蛇当宠物养。"}]', '/drɔː ðə laɪn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:38'),
(20589, 'draw', 'draw to a close/end', '[{"example": "The summer holiday is drawing to a close.", "meaning": "接近结束", "part_of_speech": "verb phrase", "example_chinese": "暑假即将结束。"}]', '/drɔː tə ə kləʊz/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:36'),
(20590, 'dread', 'dread', '[{"example": "The child felt dread before the dentist visit.", "meaning": "恐惧，畏惧", "part_of_speech": "noun", "example_chinese": "孩子在去看牙医前感到恐惧。"}]', 'dred', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:46'),
(20591, 'drift', 'drift', '[{"example": "The drift of the boat was calm on the lake.", "meaning": "漂流；趋势", "part_of_speech": "noun", "example_chinese": "小船在湖面上平静地漂流。"}]', 'drɪft', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:40'),
