(20593, 'drift', 'drift apart', '[{"example": "Over the years, childhood friends may drift apart.", "meaning": "逐渐疏远", "part_of_speech": "verb phrase", "example_chinese": "随着岁月流逝，儿时朋友可能会逐渐疏远。"}]', '/drɪft əˈpɑːt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:44'),
(20594, 'drift', 'drift off', '[{"example": "The baby drifted off while listening to the lullaby.", "meaning": "渐渐入睡", "part_of_speech": "verb", "example_chinese": "宝宝听着摇篮曲渐渐睡着了。"}]', '/drɪft ɒf/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:45'),
(20596, 'drive', 'drive sb/sth out', '[{"example": "The new policy aims to drive out illegal vendors from the downtown area.", "meaning": "驱逐/赶走", "part_of_speech": "phrasal verb", "example_chinese": "新政策旨在将非法摊贩从市中心驱逐出去。"}]', '/draɪv aʊt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:41'),
(20597, 'bend', 'drive/send sb round the bend', '[{"example": "The constant noise drives me round the bend!", "meaning": "使某人发疯/恼火", "part_of_speech": "phrasal verb", "example_chinese": "持续的噪音快把我逼疯了！"}]', '/draɪv/sɛnd ˈsʌmbədi raʊnd ðə bɛnd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:52'),
(20598, 'dead', 'drop dead', '[{"example": "He told his annoying neighbor to drop dead.", "meaning": "突然死亡；去死（粗鲁表达）", "part_of_speech": "verb", "example_chinese": "他让烦人的邻居去死。"}, {"example": "She looked drop dead gorgeous in that red dress.", "meaning": "极其迷人的", "part_of_speech": "adjective", "example_chinese": "她穿那条红裙子美得令人窒息。"}]', '/drɒp ded/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:13'),
(20600, 'drop', 'drop it/the subject', '[{"example": "When Mom started getting angry, Dad said ''Okay, let''s drop the subject.''", "meaning": "停止讨论；不再提起", "part_of_speech": "verb phrase", "example_chinese": "当妈妈开始生气时，爸爸说''好吧，我们别再提这件事了。''"}]', '/drɒp ɪt/ðə ˈsʌbdʒɪkt/', 'C2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 17:01:05'),
