(20605, 'dry', 'dry up', '[{"example": "The river dried up in the summer heat.", "meaning": "干涸；枯竭", "part_of_speech": "verb", "example_chinese": "河流在夏日高温下干涸了。"}, {"example": "Can you help me dry up the dishes?", "meaning": "擦干餐具", "part_of_speech": "verb", "example_chinese": "你能帮我擦干餐具吗？"}]', '/draɪ ʌp/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:09'),
(20606, 'dubious', 'dubious', '[{"example": "He gave a dubious answer to my question.", "meaning": "可疑的；不确定的", "part_of_speech": "adjective", "example_chinese": "他对我的问题给出了一个含糊其辞的回答。"}, {"example": "The product came from a dubious source.", "meaning": "不可靠的；质量差的", "part_of_speech": "adjective", "example_chinese": "这个产品来源不可靠。"}]', 'ˈdjuː.bi.əs', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:53'),
(20612, 'dump', 'dump sth on/in/down, etc.', '[{"example": "He dumped his bag on the floor and ran outside.", "meaning": "倾倒；扔下", "part_of_speech": "verb", "example_chinese": "他把包扔在地上就跑出去了。"}, {"example": "She dumped all her old toys in the bin.", "meaning": "抛弃；甩掉", "part_of_speech": "verb", "example_chinese": "她把所有旧玩具都扔进了垃圾桶。"}, {"example": "The company was accused of dumping cheap goods in the market.", "meaning": "倾销", "part_of_speech": "verb", "example_chinese": "这家公司被指控在市场上倾销廉价商品。"}]', '/dʌmp/', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:01:02'),
(20614, 'early', 'early on', '[{"example": "She showed great talent early on in her career.", "meaning": "在早期；在初期", "part_of_speech": "adverb", "example_chinese": "她在职业生涯早期就展现出巨大天赋。"}]', '/ˈɜːli ɒn/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:00:59'),
