(20617, 'eccentric', 'eccentric', '[{"example": "The eccentric inventor built a flying bicycle.", "meaning": "古怪的，反常的", "part_of_speech": "adjective", "example_chinese": "那位古怪的发明家造了一辆会飞的自行车。"}, {"example": "The old man was known as the village eccentric.", "meaning": "怪人", "part_of_speech": "noun", "example_chinese": "那位老人是村里有名的怪人。"}]', 'ɪkˈsen.trɪk', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 17:01:09'),
(20618, 'echo', 'echo', '[{"example": "The echo in the valley was so clear.", "meaning": "回声；回响", "part_of_speech": "noun", "example_chinese": "山谷里的回声非常清晰。"}]', 'ˈe.kəʊ', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:13'),
(20621, 'order', 'economic/political/social order', '[{"example": "The government works to maintain a stable economic order.", "meaning": "经济秩序", "part_of_speech": "noun", "example_chinese": "政府致力于维持稳定的经济秩序。"}, {"example": "After the election, the country restored its political order.", "meaning": "政治秩序", "part_of_speech": "noun", "example_chinese": "选举后，国家恢复了政治秩序。"}, {"example": "Respecting laws helps protect the social order.", "meaning": "社会秩序", "part_of_speech": "noun", "example_chinese": "尊重法律有助于维护社会秩序。"}]', '/ˌiːkəˈnɒmɪk ˈɔːdə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:28'),
(20623, 'elaborate', 'elaborate', '[{"example": "She wore an elaborate dress to the party.", "meaning": "精心制作的；复杂的", "part_of_speech": "adjective", "example_chinese": "她穿了一件精心制作的裙子去参加派对。"}, {"example": "Can you elaborate on your plan?", "meaning": "详细说明；精心制作", "part_of_speech": "verb", "example_chinese": "你能详细说明一下你的计划吗？"}]', 'ɪˈlæb.ə.rət', 'C2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 17:01:22'),
(20624, 'elapse', 'elapse', '[{"example": "Three years have elapsed since we last met.", "meaning": "（时间）流逝", "part_of_speech": "verb", "example_chinese": "自从我们上次见面，三年已经过去了。"}]', 'ɪˈlæps', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:18'),
(20625, 'elated', 'elated', '[{"example": "She was elated after winning the competition.", "meaning": "兴高采烈的，欢欣鼓舞的", "part_of_speech": "adjective", "example_chinese": "赢得比赛后她兴高采烈。"}]', 'ɪˈleɪ.tɪd', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 17:01:14'),
(20627, 'elimination', 'elimination', '[{"example": "The elimination of plastic waste helps protect our oceans.", "meaning": "消除，淘汰", "part_of_speech": "noun", "example_chinese": "消除塑料垃圾有助于保护我们的海洋。"}]', 'ɪˌlɪm.ɪˈneɪ.ʃən', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:18'),
(20628, 'elusive', 'elusive', '[{"example": "The elusive butterfly finally landed on the flower.", "meaning": "难以捉摸的；难以找到的", "part_of_speech": "adjective", "example_chinese": "那只难以捉摸的蝴蝶终于落在了花上。"}]', 'ɪˈluː.sɪv', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:23'),
(20629, 'embarrass', 'embarrass', '[{"example": "He tripped and spilled his drink, which really embarrassed him.", "meaning": "使尴尬，使窘迫", "part_of_speech": "verb", "example_chinese": "他绊了一下，饮料洒了，这让他非常尴尬。"}]', 'ɪmˈbær.əs', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:01:28'),
