(21867, 'job', 'out of a job', '[{"example": "After the factory closed, he was out of a job.", "meaning": "失业的", "part_of_speech": "adjective", "example_chinese": "工厂关闭后，他失业了。"}]', '/aʊt əv ə dʒɒb/', 'C2', 'medium', 'work', '2025-10-20 08:00:00', '2025-10-21 17:21:42'),
