(21873, 'out of', 'out of proportion', '[{"example": "His anger was out of proportion to the small mistake.", "meaning": "不成比例的，不相称的", "part_of_speech": "adjective", "example_chinese": "他的愤怒与这个小错误不成比例。"}]', '/aʊt əv prəˈpɔːʃən/', 'C2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 17:21:51'),
(21877, 'out of', 'out of shape', '[{"example": "After months without exercise, I''m completely out of shape.", "meaning": "身体走样的；健康状况不佳的", "part_of_speech": "adjective", "example_chinese": "几个月没锻炼后，我完全走样了。"}, {"example": "The old hat was out of shape after being crushed.", "meaning": "变形的；状态不好的", "part_of_speech": "adjective", "example_chinese": "这顶旧帽子被压扁后变形了。"}]', '/aʊt əv ʃeɪp/', 'C2', 'medium', 'body and health', '2025-10-20 08:00:00', '2025-10-21 17:21:55'),
(21879, 'ordinary', 'out of the ordinary', '[{"example": "The magician''s trick was truly out of the ordinary.", "meaning": "不寻常的，非凡的", "part_of_speech": "adjective", "example_chinese": "魔术师的把戏确实非同寻常。"}]', '/aʊt əv ði ˈɔːdənri/', 'C2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 17:21:55'),
(21881, 'depth', 'out of your depth', '[{"example": "When they started discussing quantum physics, I was completely out of my depth.", "meaning": "力所不及；处于无法应付的境地", "part_of_speech": "phrase", "example_chinese": "当他们开始讨论量子物理时，我完全听不懂。"}]', '/aʊt əv jɔːr depθ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:21:56'),
(21883, 'output', 'output', '[{"example": "The computer''s output is displayed on the screen.", "meaning": "输出；产量", "part_of_speech": "noun", "example_chinese": "计算机的输出显示在屏幕上。"}]', 'ˈaʊt.pʊt', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:21:50'),
(21886, 'welcome', 'outstay/overstay your welcome', '[{"example": "He overstayed his welcome by talking for three hours.", "meaning": "逗留过久而惹人厌烦", "part_of_speech": "verb", "example_chinese": "他聊了三个小时，逗留太久让人厌烦。"}]', '/ˌəʊvəˈsteɪ jɔː ˈwelkəm/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:01'),
(21889, 'overboard', 'overboard', '[{"example": "The sailor fell overboard during the storm.", "meaning": "从船上掉入水中；过度地", "part_of_speech": "adverb", "example_chinese": "水手在暴风雨中从船上落水了。"}, {"example": "His reaction was completely overboard.", "meaning": "过分的", "part_of_speech": "adjective", "example_chinese": "他的反应完全过分了。"}]', 'ˈəʊ.və.bɔːd', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:03'),
(21890, 'overflow', 'overflow', '[{"example": "The river overflow flooded the streets.", "meaning": "溢出；泛滥", "part_of_speech": "noun", "example_chinese": "河流泛滥淹没了街道。"}, {"example": "Her happiness overflows when she sees puppies.", "meaning": "溢出；充满", "part_of_speech": "verb", "example_chinese": "看到小狗时她的快乐溢于言表。"}]', 'ˌəʊ.vəˈfləʊ', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:03'),
(21892, 'overflow', 'overflow with confidence/happiness/love, etc.', '[{"example": "Her eyes overflowed with happiness when she saw the surprise.", "meaning": "充满自信/幸福/爱等", "part_of_speech": "verb", "example_chinese": "看到惊喜时，她的眼中洋溢着幸福。"}]', '/ˌəʊvəˈfləʊ wɪð/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:08'),
(21893, 'overhear', 'overhear', '[{"example": "I overheard them talking about the surprise party.", "meaning": "无意中听到，偶然听见", "part_of_speech": "verb", "example_chinese": "我无意中听到他们在讨论惊喜派对。"}]', 'ˌəʊ.vəˈhɪər', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:11'),
(21894, 'overlap', 'overlap', '[{"example": "There is some overlap between the two circles.", "meaning": "重叠部分", "part_of_speech": "noun", "example_chinese": "两个圆圈之间有部分重叠"}]', 'ˌəʊ.vəˈlæp', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:13'),
(21895, 'overload', 'overload', '[{"example": "The electrical overload caused a blackout in the building.", "meaning": "超负荷；过载", "part_of_speech": "noun", "example_chinese": "电力超负荷导致大楼停电。"}]', 'ˌəʊ.vəˈləʊd', 'C2', 'medium', 'work', '2025-10-20 08:00:00', '2025-10-21 17:22:13'),
(21899, 'over', 'over the top', '[{"example": "His reaction was completely over the top when he saw the surprise.", "meaning": "夸张的，过火的", "part_of_speech": "adjective", "example_chinese": "他看到惊喜时的反应完全夸张过头了。"}]', '/ˌəʊvə ðə ˈtɒp/', 'C2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 17:22:18'),
(21901, 'owe', 'owe your existence/success, etc. to sb/sth', '[{"example": "I owe my success to my teacher''s guidance.", "meaning": "将...归功于", "part_of_speech": "verb", "example_chinese": "我的成功归功于老师的指导。"}]', '/əʊ jɔːr ˌɛɡzɪˈstəns ˈsʌksɛs tʊ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:16'),
(21902, 'own', 'own up', '[{"example": "He finally owned up to eating the last cookie.", "meaning": "坦白承认", "part_of_speech": "verb", "example_chinese": "他终于承认吃了最后一块饼干。"}]', '/əʊn ʌp/', 'C2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 17:22:21'),
(21903, 'pace', 'pace about/up and down, etc', '[{"example": "The lion paced about in its cage.", "meaning": "踱步，来回走动", "part_of_speech": "verb", "example_chinese": "狮子在笼子里踱步。"}, {"example": "She paced up and down while waiting for the test results.", "meaning": "焦虑地走来走去", "part_of_speech": "verb", "example_chinese": "她在等待测试结果时焦虑地走来走去。"}]', '/peɪs əˈbaʊt/', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:22:21'),
(21904, 'pace', 'pace yourself', '[{"example": "Don''t run too fast at the beginning of the race—you need to pace yourself.", "meaning": "控制节奏；量力而行", "part_of_speech": "verb_phrase", "example_chinese": "比赛开始时别跑太快，你需要控制节奏。"}]', '/peɪs jɔːrˈself/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:24'),
(21906, 'pact', 'pact', '[{"example": "The two countries signed a peace pact to end the war.", "meaning": "协定；条约；契约", "part_of_speech": "noun", "example_chinese": "两国签署了和平协定以结束战争。"}]', 'pækt', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:26'),
(21910, 'paradigm', 'paradigm', '[{"example": "The discovery caused a paradigm shift in science.", "meaning": "范式；典范", "part_of_speech": "noun", "example_chinese": "这一发现引发了科学界的范式转变。"}]', 'ˈpær.ə.daɪm', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:29'),
(21911, 'paradox', 'paradox', '[{"example": "It''s a paradox that standing is more tiring than walking.", "meaning": "悖论；自相矛盾的人或事", "part_of_speech": "noun", "example_chinese": "站着比走路更累是个悖论。"}]', 'ˈpær.ə.dɒks', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:34'),
(21912, 'paradoxical', 'paradoxical', '[{"example": "It''s paradoxical that standing is more tiring than walking.", "meaning": "矛盾的；似非而是的", "part_of_speech": "adjective", "example_chinese": "站着比走路更累，这很矛盾。"}]', 'ˌpær.əˈdɒk.sɪ.kəl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:36'),
(21913, 'parallel', 'parallel', '[{"example": "The two roads run in parallel.", "meaning": "平行线", "part_of_speech": "noun", "example_chinese": "这两条路平行延伸。"}]', 'ˈpær.ə.lel', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:31'),
(21915, 'paramount', 'paramount', '[{"example": "Safety is paramount when working in the laboratory.", "meaning": "最重要的，至高无上的", "part_of_speech": "adjective", "example_chinese": "在实验室工作时，安全是最重要的。"}]', 'ˈpær.ə.maʊnt', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:38'),
(21918, 'parcel', 'part and parcel', '[{"example": "Making mistakes is part and parcel of learning English.", "meaning": "必要组成部分，不可或缺的部分", "part_of_speech": "noun", "example_chinese": "犯错是学习英语必不可少的一部分。"}]', '/ˌpɑːt ən ˈpɑːs(ə)l/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:36'),
(21920, 'particle', 'particle', '[{"example": "Dust particles floated in the sunlight.", "meaning": "微粒，粒子", "part_of_speech": "noun", "example_chinese": "尘埃微粒在阳光下漂浮。"}, {"example": "''Up'' is a particle in ''look up''.", "meaning": "虚词，小品词", "part_of_speech": "noun", "example_chinese": "在''look up''中，''up''是个小品词。"}]', 'ˈpɑː.tɪk.l', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:48'),
(21926, 'pastime', 'pastime', '[{"example": "Reading is my favorite pastime on weekends.", "meaning": "消遣；娱乐", "part_of_speech": "noun", "example_chinese": "阅读是我周末最喜欢的消遣。"}]', 'ˈpɑːs.taɪm', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:41'),
(21927, 'pat', 'pat', '[{"example": "The mother patted the baby''s back gently.", "meaning": "轻拍", "part_of_speech": "verb", "example_chinese": "妈妈轻轻拍了拍宝宝的背。"}, {"example": "He gave the dog a friendly pat on the head.", "meaning": "轻拍", "part_of_speech": "noun", "example_chinese": "他友好地拍了拍狗的头。"}]', 'pæt', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:22:45'),
(21928, 'patch', 'patch', '[{"example": "He sewed a patch on his jeans.", "meaning": "补丁", "part_of_speech": "noun", "example_chinese": "他在牛仔裤上缝了个补丁。"}, {"example": "We found a patch of strawberries in the forest.", "meaning": "小块区域", "part_of_speech": "noun", "example_chinese": "我们在森林里发现了一小块草莓地。"}, {"example": "She patched the hole in the tent.", "meaning": "修补", "part_of_speech": "verb", "example_chinese": "她修补了帐篷上的洞。"}]', 'pætʃ', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:57'),
(21932, 'patch', 'patch sth up', '[{"example": "They patched up their argument with a hug.", "meaning": "修补；修复（关系）", "part_of_speech": "phrasal verb", "example_chinese": "他们用一个拥抱修补了争吵。"}]', '/pætʃ ʌp/', 'C2', 'medium', 'relationships', '2025-10-20 08:00:00', '2025-10-21 17:22:55'),
(21934, 'pathetic', 'pathetic', '[{"example": "His pathetic attempt to cook made us laugh.", "meaning": "可怜的，可悲的", "part_of_speech": "adjective", "example_chinese": "他糟糕的烹饪尝试让我们发笑。"}]', 'pəˈθet.ɪk', 'C2', 'medium', 'describing things', '2025-10-20 08:00:00', '2025-10-21 17:22:46'),
(21936, 'way', 'pave the way', '[{"example": "His research paved the way for new discoveries.", "meaning": "为...铺平道路", "part_of_speech": "verb phrase", "example_chinese": "他的研究为新发现铺平了道路。"}]', '/peɪv ðə weɪ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:50'),
(21938, 'compliment', 'pay sb a compliment', '[{"example": "She paid him a compliment on his cooking skills.", "meaning": "称赞某人", "part_of_speech": "verb", "example_chinese": "她称赞了他的厨艺。"}]', '/peɪ sʌmbədi ə ˈkɒmplɪmənt/', 'C2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 17:22:50'),
(21940, 'pay', 'pay the price', '[{"example": "If you don''t study, you''ll pay the price in the exam.", "meaning": "付出代价", "part_of_speech": "verb_phrase", "example_chinese": "如果你不学习，考试时就会付出代价。"}]', '/peɪ ðə praɪs/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:22:55'),
(21942, 'pay', 'pay tribute to sb/sth', '[{"example": "We pay tribute to our brave firefighters.", "meaning": "向…致敬/赞扬", "part_of_speech": "verb", "example_chinese": "我们向勇敢的消防员致敬。"}]', '/peɪ ˈtrɪbjuːt tuː/', 'C2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 17:23:02');
INSERT INTO `words` (`word_id`, `headword`, `base_form`, `translation`, `uk_pron`, `cefr_level`, `frequency`, `topic`, `created_at`, `updated_at`) VALUES
(21944, 'mind', 'peace of mind', '[{"example": "Meditation gives me peace of mind.", "meaning": "内心的平静，安心", "part_of_speech": "noun", "example_chinese": "冥想让我内心平静。"}]', '/piːs əv maɪnd/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:05'),
(21946, 'peculiar', 'peculiar to sb/sth', '[{"example": "This custom is peculiar to this village.", "meaning": "某人/某物特有的", "part_of_speech": "adjective", "example_chinese": "这个习俗是这个村庄特有的。"}]', '/pɪˈkjuːliə(r) tuː/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:07'),
(21948, 'peep', 'peep at/through/out, etc.', '[{"example": "The child peeped through the keyhole.", "meaning": "偷看，窥视", "part_of_speech": "verb", "example_chinese": "孩子从钥匙孔里偷看。"}, {"example": "The sun peeped out from behind the clouds.", "meaning": "微现，露出", "part_of_speech": "verb", "example_chinese": "太阳从云层后微微露出。"}, {"example": "She took a quick peep at the birthday presents.", "meaning": "窥视，一瞥", "part_of_speech": "noun", "example_chinese": "她快速瞥了一眼生日礼物。"}]', '/piːp/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:16'),
(21949, 'peer', 'peer at/into/through, etc.', '[{"example": "The child peered through the keyhole to see the surprise.", "meaning": "仔细看；凝视；费力地看", "part_of_speech": "verb", "example_chinese": "孩子透过钥匙孔窥视惊喜"}]', '/pɪər/', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:23:10'),
(21950, 'peer pressure', 'peer pressure', '[{"example": "Teenagers often face peer pressure to try new things.", "meaning": "同辈压力", "part_of_speech": "noun", "example_chinese": "青少年常因同辈压力尝试新事物。"}]', 'ˈpiəˌpreʃ.ər', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:15'),
(21952, 'perception', 'perception', '[{"example": "Children''s perception of the world is often magical.", "meaning": "感知，看法", "part_of_speech": "noun", "example_chinese": "孩子们对世界的感知常常充满魔力。"}]', 'pəˈsep.ʃən', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:13'),
(21953, 'perceptive', 'perceptive', '[{"example": "The perceptive child noticed the hidden clue in the story.", "meaning": "有洞察力的；敏锐的", "part_of_speech": "adjective", "example_chinese": "这个敏锐的孩子发现了故事中隐藏的线索。"}]', 'pəˈsep.tɪv', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 17:23:21'),
(21956, 'perseverance', 'perseverance', '[{"example": "Her perseverance in learning English finally paid off.", "meaning": "毅力；坚持不懈", "part_of_speech": "noun", "example_chinese": "她学习英语的毅力终于得到了回报。"}]', 'ˌpɜː.sɪˈvɪə.rənts', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:18'),
(21957, 'persist', 'persist', '[{"example": "If you persist in practicing, you will master English.", "meaning": "坚持；持续", "part_of_speech": "verb", "example_chinese": "如果你坚持练习，就能掌握英语。"}]', 'pəˈsɪst', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:25'),
(21959, 'persistence', 'persistence', '[{"example": "Her persistence in practicing piano made her a great musician.", "meaning": "坚持不懈；持续存在", "part_of_speech": "noun", "example_chinese": "她坚持练习钢琴，这使她成为了一位伟大的音乐家。"}]', 'pəˈsɪs.tənts', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:23'),
(21960, 'persistent', 'persistent', '[{"example": "The persistent rain lasted for three days.", "meaning": "持续的；坚持不懈的", "part_of_speech": "adjective", "example_chinese": "持续的雨下了三天。"}, {"example": "She was persistent in asking questions until she understood.", "meaning": "执着的；固执的", "part_of_speech": "adjective", "example_chinese": "她执着地问问题直到完全理解。"}]', 'pəˈsɪs.tənt', 'C2', 'medium', 'people: personality', '2025-10-20 08:00:00', '2025-10-21 17:23:30'),
(21961, 'persuasion', 'persuasion', '[{"example": "She used gentle persuasion to change his mind.", "meaning": "说服；信念", "part_of_speech": "noun", "example_chinese": "她用温和的说服改变了他的想法。"}]', 'pəˈsweɪ.ʒən', 'C2', 'medium', 'communication', '2025-10-20 08:00:00', '2025-10-21 17:23:30'),
(21962, 'petty', 'petty', '[{"example": "Don''t waste time on petty arguments.", "meaning": "琐碎的，小气的", "part_of_speech": "adjective", "example_chinese": "别在琐碎的争吵上浪费时间。"}]', 'ˈpet.i', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:30'),
(21963, 'phenomenal', 'phenomenal', '[{"example": "The fireworks show was absolutely phenomenal!", "meaning": "非凡的；惊人的；极好的", "part_of_speech": "adjective", "example_chinese": "这场烟花表演简直太精彩了！"}]', 'fɪˈnɒm.ɪ.nəl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:35'),
(21964, 'philosophical', 'philosophical', '[{"example": "He remained philosophical about losing the game.", "meaning": "哲学的；达观的", "part_of_speech": "adjective", "example_chinese": "他对输掉比赛表现得很豁达。"}]', 'ˌfɪl.əˈsɒf.ɪ.kəl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:35'),
(21967, 'pick', 'pick up the pieces', '[{"example": "After the failure, we need to pick up the pieces and start again.", "meaning": "收拾残局；重整旗鼓", "part_of_speech": "phrasal verb", "example_chinese": "失败后，我们需要收拾残局重新开始。"}, {"example": "She picked up the pieces of her life after the divorce.", "meaning": "振作起来", "part_of_speech": "phrasal verb", "example_chinese": "离婚后她重新振作起来面对生活。"}]', '/pɪk ʌp ðə ˈpiːsɪz/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:23:43'),
