(22077, 'provincial', 'provincial', '[{"example": "His provincial attitude made him uncomfortable in the cosmopolitan city.", "meaning": "省的；地方的；偏狭的", "part_of_speech": "adjective", "example_chinese": "他偏狭的态度使他在国际大都市感到不适。"}, {"example": "The provincial was amazed by the city''s tall buildings.", "meaning": "外省人；地方居民", "part_of_speech": "noun", "example_chinese": "那个外省人对城市的高楼大厦感到惊讶。"}]', 'prəˈvɪn.ʃəl', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:25:40'),
