(22154, 'reap', 'reap the benefits/profits/rewards', '[{"example": "If you study hard now, you will reap the benefits later.", "meaning": "获得好处/利润/回报", "part_of_speech": "verb", "example_chinese": "如果你现在努力学习，以后就会收获好处。"}, {"example": "The company reaped huge profits from the new product.", "meaning": "收获利益", "part_of_speech": "verb", "example_chinese": "公司从新产品中获得了巨大利润。"}, {"example": "Her hard work finally reaped rewards when she got promoted.", "meaning": "得到回报", "part_of_speech": "verb", "example_chinese": "当她获得晋升时，她的努力终于得到了回报。"}]', '/riːp ðə ˈbɛnɪfɪts/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:33:14'),
