(22179, 'reduce', 'reduce sb to sth/doing sth', '[{"example": "The bad news reduced her to tears.", "meaning": "使某人陷入某种境地/迫使某人做某事", "part_of_speech": "verb phrase", "example_chinese": "这个坏消息让她哭了。"}, {"example": "Poverty reduced him to begging.", "meaning": "使某人沦为某种状态", "part_of_speech": "verb phrase", "example_chinese": "贫穷迫使他乞讨。"}]', '/rɪˈdjuːs/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:26:12'),
