(22772, 'take', 'take a turn for the better/worse', '[{"example": "After the medicine, his health took a turn for the better.", "meaning": "好转/恶化", "part_of_speech": "phrase", "example_chinese": "服药后，他的健康状况好转了。"}, {"example": "The weather took a turn for the worse with heavy rain.", "meaning": "好转/恶化", "part_of_speech": "phrase", "example_chinese": "天气因大雨而恶化了。"}]', '/teɪk ə tɜːn fɔː ðə ˈbetə/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:37:17'),
