(23204, 'wink', 'wink', '[{"example": "He gave me a friendly wink.", "meaning": "眨眼", "part_of_speech": "verb", "example_chinese": "他对我友好地眨了下眼。"}, {"example": "She added a wink to her smile.", "meaning": "眨眼", "part_of_speech": "noun", "example_chinese": "她在微笑时加了个眨眼。"}]', 'wɪŋk', 'C2', 'medium', 'people: actions', '2025-10-20 08:00:00', '2025-10-21 17:46:14'),
(23205, 'wipe', 'wipe sth out or wipe out sth', '[{"example": "The earthquake wiped out the entire village.", "meaning": "彻底消灭/摧毁", "part_of_speech": "phrasal verb", "example_chinese": "地震摧毁了整个村庄。"}, {"example": "The marathon wiped me out completely.", "meaning": "使精疲力尽", "part_of_speech": "phrasal verb", "example_chinese": "马拉松让我精疲力尽。"}]', '/waɪp aʊt/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:46:28'),
(23207, 'breath', 'with bated breath', '[{"example": "The audience waited with bated breath for the magician''s final trick.", "meaning": "屏息以待；焦急地等待", "part_of_speech": "idiom", "example_chinese": "观众屏息以待魔术师的最终表演。"}]', '/weɪð ˈbeɪtɪd breθ/', 'C2', 'medium', '', '2025-10-20 08:00:00', '2025-10-21 17:43:17'),
