-- ----------------------------
-- 表结构: article_sentences
-- ----------------------------
DROP TABLE IF EXISTS `article_sentences`;
CREATE TABLE `article_sentences` (
  `sentence_id` int NOT NULL AUTO_INCREMENT COMMENT '句子ID（自增主键）',
  `article_id` int NOT NULL COMMENT '文章ID（关联articles表）',
  `sentence_order` int NOT NULL DEFAULT '0' COMMENT '句子顺序（从1开始）',
  `original_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '句子原文（英文）',
  `translation` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '中文翻译',
  `is_favorite` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否收藏（0=未收藏，1=已收藏）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`sentence_id`),
  KEY `idx_article_id` (`article_id`) COMMENT '按文章查询',
  KEY `idx_sentence_order` (`article_id`,`sentence_order`) COMMENT '按文章和顺序查询',
  KEY `idx_is_favorite` (`article_id`,`is_favorite`) COMMENT '按文章和收藏状态查询'
) ENGINE=InnoDB AUTO_INCREMENT=70 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='文章句子表，存储每篇文章的句子信息';

