-- ----------------------------
-- 表结构: library_words
-- ----------------------------
DROP TABLE IF EXISTS `library_words`;
CREATE TABLE `library_words` (
  `library_words_id` int NOT NULL AUTO_INCREMENT COMMENT '关联记录ID',
  `library_id` int NOT NULL COMMENT '词库ID',
  `word_id` int NOT NULL COMMENT '单词ID',
  `added_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加到词库的时间',
  `added_by` int DEFAULT NULL COMMENT '添加者用户ID(用于记录谁添加的)',
  PRIMARY KEY (`library_words_id`),
  UNIQUE KEY `idx_library_word` (`library_id`,`word_id`) COMMENT '确保同一词库中单词不重复',
  KEY `idx_library` (`library_id`) COMMENT '按词库查询',
  KEY `idx_word` (`word_id`) COMMENT '按单词查询',
  KEY `idx_added` (`added_at`) COMMENT '按添加时间排序',
  KEY `fk_library_words_user` (`added_by`),
  CONSTRAINT `fk_library_words_library` FOREIGN KEY (`library_id`) REFERENCES `libraries` (`library_id`),
  CONSTRAINT `fk_library_words_word` FOREIGN KEY (`word_id`) REFERENCES `words` (`word_id`)
) ENGINE=InnoDB AUTO_INCREMENT=170 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='词库-单词关联表';

