  PRIMARY KEY (`unit_list_id`),
  KEY `fk_libraries_owner` (`owner_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='存储所有用户创建的词库信息';

