-- ----------------------------
-- 表结构: user_library
-- ----------------------------
DROP TABLE IF EXISTS `user_library`;
CREATE TABLE `user_library` (
  `user_library_id` int NOT NULL AUTO_INCREMENT COMMENT '使用记录ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `library_id` int NOT NULL COMMENT '词库ID',
  `status` enum('subscribed','learning','completed','paused') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'subscribed' COMMENT '使用状态: subscribed-已订阅, learning-学习中, completed-已完成, paused-已暂停',
  `progress_percentage` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '学习进度百分比(0.00-100.00)',
  `words_learned` int NOT NULL DEFAULT '0' COMMENT '已学习单词数',
  `words_mastered` int NOT NULL DEFAULT '0' COMMENT '已掌握单词数',
  `total_study_time` int NOT NULL DEFAULT '0' COMMENT '总学习时间(分钟)',
  `last_studied_at` datetime DEFAULT NULL COMMENT '最后学习时间',
  `subscribed_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '订阅时间',
  `started_at` datetime DEFAULT NULL COMMENT '开始学习时间',
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`user_library_id`),
  UNIQUE KEY `idx_user_library` (`user_id`,`library_id`) COMMENT '确保用户对同一词库只有一条使用记录',
  KEY `idx_user_status` (`user_id`,`status`) COMMENT '按用户和状态查询',
  KEY `idx_library_status` (`library_id`,`status`) COMMENT '按词库和状态查询',
  KEY `idx_progress` (`progress_percentage`) COMMENT '按学习进度排序',
  KEY `idx_last_studied` (`last_studied_at`) COMMENT '按最后学习时间排序',
  KEY `idx_subscribed` (`subscribed_at`) COMMENT '按订阅时间排序',
  KEY `idx_user_status_progress` (`user_id`,`status`,`progress_percentage`),
  KEY `idx_library_progress` (`library_id`,`progress_percentage`),
  KEY `idx_last_studied_status` (`last_studied_at`,`status`),
  CONSTRAINT `fk_user_library_library` FOREIGN KEY (`library_id`) REFERENCES `libraries` (`library_id`),
  CONSTRAINT `fk_user_library_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='存储用户选择了哪些词库，用于用户的词库列表展示';

