-- ----------------------------
-- 表结构: user_study_queue
-- ----------------------------
DROP TABLE IF EXISTS `user_study_queue`;
CREATE TABLE `user_study_queue` (
  `queue_id` int NOT NULL AUTO_INCREMENT COMMENT '学词库记录ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `word_id` int NOT NULL COMMENT '单词ID',
  `library_id` int NOT NULL COMMENT '词库ID',
  `library_words_id` int NOT NULL COMMENT '单词在该词库中的ID',
  `status` enum('pending','learning','mastered') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '学习状态: pending-待学, learning-学习中, mastered-已掌握',
  `added_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加到学词库的时间',
  `started_at` datetime DEFAULT NULL COMMENT '开始学习时间',
  `mastered_at` datetime DEFAULT NULL COMMENT '掌握时间',
  `priority` tinyint NOT NULL DEFAULT '0' COMMENT '学习优先级(0-普通,1-重要,2-紧急)',
  `review_count` int NOT NULL DEFAULT '0' COMMENT '复习次数',
  `last_reviewed` datetime DEFAULT NULL COMMENT '最后复习时间',
  `next_review` datetime DEFAULT NULL COMMENT '下次复习时间',
  PRIMARY KEY (`queue_id`),
  UNIQUE KEY `idx_user_word` (`user_id`,`word_id`) COMMENT '确保每个单词在用户学词库中唯一',
  KEY `idx_user_status` (`user_id`,`status`) COMMENT '按用户和学习状态查询',
  KEY `idx_user_priority` (`user_id`,`priority`,`added_at`) COMMENT '按优先级和添加时间排序',
  KEY `idx_user_review` (`user_id`,`next_review`) COMMENT '用于复习提醒',
  KEY `fk_queue_library` (`library_id`) USING BTREE,
  KEY `fk_study_queue_word` (`word_id`),
  CONSTRAINT `fk_queue_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE,
  CONSTRAINT `fk_study_queue_library` FOREIGN KEY (`library_id`) REFERENCES `libraries` (`library_id`),
  CONSTRAINT `fk_study_queue_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`),
  CONSTRAINT `fk_study_queue_word` FOREIGN KEY (`word_id`) REFERENCES `words` (`word_id`)
) ENGINE=InnoDB AUTO_INCREMENT=164 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户学词库，管理用户当前学习队列和进度';

